{n:6,lang:"de",srcLang:"en",track:"v2",title:"Alles auf Deutsch",sub:"Daily life, health, work, hobbies & Hildi's tea",icon:"☕",level:"A1.2",color:"#7B5EE8",lessons:[

// ─── L1: Kaltes Wasser! ───
{id:"deu_r6l1",title:"Kaltes Wasser!",icon:"🚿",xp:15,board:true,steps:[
{type:"intro",title:"Alles auf Deutsch",desc:"Verumius is settling into his apartment. But the hot water is gone. Time to learn daily routine, body parts, and past tense of sein/haben.",goals:["Daily routine vocabulary","Body parts","Past tense: war/hatte"]},
{type:"teach",trg:"die Dusche",src:"the shower",pos:"noun",gender:"f",note:"Feminine. Also the verb: duschen (to shower).",example:"A: Die Dusche ist kalt!\nB: Oh nein! Kein heißes Wasser?",exampleSrc:"A: The shower is cold!\nB: Oh no! No hot water?",funFact:"Germans love their showers. Average shower time: 6 minutes. Hildi's Hausordnung has a section on shower times."},
{type:"teach",trg:"duschen",src:"to shower",pos:"verb",gender:null,note:"Regular. Reflexive in formal German (sich duschen).",example:"A: Ich dusche jeden Morgen.\nB: Warm oder kalt?",exampleSrc:"A: I shower every morning.\nB: Warm or cold?",funFact:"In everyday speech, Germans drop the 'sich': 'Ich dusche' instead of 'Ich dusche mich.' Both correct."},
{type:"teach",trg:"der Schlaf",src:"sleep",pos:"noun",gender:"m",note:"Masculine. No plural. Verb: schlafen (irregular: schläft).",example:"A: Gute Nacht! Schlaf gut!\nB: Danke, dir auch!",exampleSrc:"A: Good night! Sleep well!\nB: Thanks, you too!",funFact:"'Schönheitsschlaf' = beauty sleep. Germans take it seriously."},
{type:"teach",trg:"schlafen",src:"to sleep",pos:"verb",gender:null,note:"Irregular: ich schlafe, du schläfst, er schläft.",example:"A: Wie lange schläfst du?\nB: Ich schlafe acht Stunden.",exampleSrc:"A: How long do you sleep?\nB: I sleep eight hours.",funFact:"Stem vowel change: a to ä in du/er forms. One of the first strong verbs you meet."},
{type:"verb_table",title:"schlafen (to sleep)",groups:[{label:"Present tense (stem change: a → ä)",rows:[{pronoun:"ich",form:"schlafe",src:"I sleep"},{pronoun:"du",form:"schläfst",src:"you sleep"},{pronoun:"er/sie/es",form:"schläft",src:"he/she/it sleeps"},{pronoun:"wir",form:"schlafen",src:"we sleep"},{pronoun:"ihr",form:"schlaft",src:"you all sleep"},{pronoun:"sie/Sie",form:"schlafen",src:"they/you (formal) sleep"}]}],note:"Same a → ä pattern as fahren and waschen."},
{type:"teach",trg:"einschlafen",src:"to fall asleep",pos:"verb",gender:null,note:"Separable: ich schlafe ein. Irregular like schlafen.",example:"A: Wann schläfst du ein?\nB: Ich schlafe um elf ein.",exampleSrc:"A: When do you fall asleep?\nB: I fall asleep at eleven.",funFact:"Separable! 'Ich schlafe ein' = I fall asleep. The 'ein' flies to the end."},
{type:"teach",trg:"wecken",src:"to wake (someone)",pos:"verb",gender:null,note:"Regular. 'Der Wecker' = alarm clock.",example:"A: Weck mich um sieben!\nB: Okay, ich wecke dich.",exampleSrc:"A: Wake me at seven!\nB: Okay, I'll wake you.",funFact:"Not to confuse with 'Wecken' (bread roll in southern Germany). Context saves you."},
{type:"teach",trg:"der Hunger",src:"hunger",pos:"noun",gender:"m",note:"Masculine. 'Ich habe Hunger' = I am hungry.",example:"A: Hast du Hunger?\nB: Ja, großen Hunger!",exampleSrc:"A: Are you hungry?\nB: Yes, very hungry!",funFact:"'Bärenhunger' = bear's hunger = starving. Germans love animal metaphors."},
{type:"fb",s:"Du {1} jeden Tag um sieben Uhr.",a:["schläfst"],opts:["schläfst","schlafe","schlafen","schlaft"],hint:"Second person singular of schlafen. Vowel change a to ä.",sSrc:"You sleep every day at seven o'clock."},
{type:"mc",q:"'Ich habe Hunger' bedeutet:",opts:["Ich bin hungrig.","Ich bin müde.","Ich bin krank.","Ich bin durstig."],ans:"Ich bin hungrig.",hint:"Hunger relates to wanting food."},
{type:"teach",trg:"der Durst",src:"thirst",pos:"noun",gender:"m",note:"Masculine. 'Ich habe Durst' = I am thirsty.",example:"A: Ich habe Durst.\nB: Möchtest du Wasser?",exampleSrc:"A: I'm thirsty.\nB: Would you like water?",funFact:"Used with haben, not sein. 'Ich habe Durst,' never 'Ich bin Durst.'"},
{type:"teach",trg:"spazieren gehen",src:"to go for a walk",pos:"verb",gender:null,note:"Two-verb combo. 'Ich gehe spazieren.'",example:"A: Gehst du spazieren?\nB: Ja, im Park.",exampleSrc:"A: Are you going for a walk?\nB: Yes, in the park.",funFact:"Germans walk A LOT. 'Sonntagsspaziergang' = Sunday stroll. A genuine German tradition."},
{type:"teach",trg:"früh",src:"early",pos:"adj",gender:null,note:"Adjective/adverb. Opposite: spät (late).",example:"A: Es ist zu früh!\nB: Der frühe Vogel fängt den Wurm.",exampleSrc:"A: It's too early!\nB: The early bird catches the worm.",funFact:"Same proverb! 'Der frühe Vogel fängt den Wurm.' Germans are early risers."},
{type:"teach",trg:"fertig",src:"finished / ready",pos:"adj",gender:null,note:"Means both! Context decides.",example:"A: Bist du fertig?\nB: Ja, ich bin fertig!",exampleSrc:"A: Are you done/ready?\nB: Yes, I'm done/ready!",funFact:"'Fertig' = finished AND ready. 'Das Essen ist fertig' = dinner is ready. 'Ich bin fertig' = I'm done."},
{type:"fb",s:"Bist du {1}? Wir müssen gehen!",a:["fertig"],opts:["fertig","früh","spät","krank"],hint:"Are you ready or done? This word means both.",sSrc:"Are you ready? We have to go!"},
{type:"teach",trg:"der Kopf / die Hand / der Arm / der Bauch",src:"head / hand / arm / belly",pos:"noun",gender:"m",note:"Body parts: der Kopf (m), die Hand (f), der Arm (m), der Bauch (m).",example:"A: Mein Kopf!\nB: Und meine Hand auch!",exampleSrc:"A: My head!\nB: And my hand too!",funFact:"Hand is one of the few German body parts that is feminine. Most are masculine."},
{type:"teach",trg:"der Rücken / das Bein / der Fuß / der Finger",src:"back / leg / foot / finger",pos:"noun",gender:"m",note:"More body parts. das Bein is neuter!",example:"A: Mein Rücken tut weh.\nB: Und mein Bein auch!",exampleSrc:"A: My back hurts.\nB: And my leg too!",funFact:"Fuß is cognate with English 'foot.' The ß in Fuß shows a long vowel. Plural: Füße."},
{type:"tip",title:"Past Tense: war / hatte",text:"In spoken German, ONLY sein and haben use simple past:\n\nwar (was): ich war, du warst, er war, wir waren\nhatte (had): ich hatte, du hattest, er hatte, wir hatten\n\n'Das Wasser war kalt.'\n'Ich hatte Hunger.'\n\nEverything else uses Perfekt (coming in A2).",deepDive:{title:"When to use Präteritum vs Perfekt",text:"Perfekt is the default past tense in spoken German:\n'Ich habe gestern Pizza gegessen.' (I ate pizza yesterday.)\n\nPräteritum is used in:\n1. Written narratives, stories, news articles\n2. sein and haben (war/hatte) even in speech\n3. Modal verbs (konnte, musste, wollte) even in speech\n4. Formal written German\n\nThink of it this way: if you are TELLING a story or WRITING, use Präteritum. If you are CHATTING about your day, use Perfekt, except for war/hatte."}},
{type:"verb_table",title:"Präteritum: sein (to be)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"war",src:"I was"},{pronoun:"du",form:"warst",src:"you were"},{pronoun:"er/sie/es",form:"war",src:"he/she/it was"}]},{label:"Plural",rows:[{pronoun:"wir",form:"waren",src:"we were"},{pronoun:"ihr",form:"wart",src:"you all were"},{pronoun:"sie/Sie",form:"waren",src:"they were / you were (formal)"}]}],note:"Only 4 forms: war, warst, wart, waren. ich and er/sie/es share the same form: war."},
{type:"verb_table",title:"Präteritum: haben (to have)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"hatte",src:"I had"},{pronoun:"du",form:"hattest",src:"you had"},{pronoun:"er/sie/es",form:"hatte",src:"he/she/it had"}]},{label:"Plural",rows:[{pronoun:"wir",form:"hatten",src:"we had"},{pronoun:"ihr",form:"hattet",src:"you all had"},{pronoun:"sie/Sie",form:"hatten",src:"they had / you had (formal)"}]}],note:"Only 4 forms: hatte, hattest, hattet, hatten. ich and er/sie/es share the same form: hatte."},
{type:"mc",q:"'Das Wasser ___ kalt.'",opts:["hatte","war","ist","hat"],ans:"war",hint:"Simple past of sein. The water WAS cold."},
{type:"fb",s:"Ich {1} gestern großen Hunger.",a:["hatte"],opts:["hatte","war","habe","bin"],hint:"Past tense of haben. I HAD hunger.",sSrc:"I had great hunger yesterday."},
{type:"mc",q:"'Ich ___ jeden Morgen.'",opts:["frühstücken","schlafe","frühstücke","dusche"],ans:"frühstücke",hint:"What do you do with food in the morning? First person singular."},
{type:"match",pairs:[{trg:"der Kopf",src:"head"},{trg:"die Hand",src:"hand"},{trg:"der Fuß",src:"foot"},{trg:"der Bauch",src:"belly"},{trg:"das Bein",src:"leg"}]}
]},

// ─── L2: Mein Tag ───
{id:"deu_r6l2",title:"Mein Tag",icon:"⏰",xp:15,board:true,steps:[
{type:"intro",title:"Mein Tag",desc:"Time words, clock expressions, and daily scheduling. The backbone of German life: everything runs on time.",goals:["Time nouns and adverbs","Clock expressions: um + Uhr","Yesterday/today/tomorrow"]},
{type:"teach",trg:"der Tag",src:"the day",pos:"noun",gender:"m",note:"Masculine. Also means 'hello' in southern Germany! 'Tag!'",example:"A: Was für ein Tag!\nB: Ja, ein guter Tag!",exampleSrc:"A: What a day!\nB: Yes, a good day!",funFact:"'Tag!' is a casual greeting in southern Germany. Just the word 'day' as a hello."},
{type:"teach",trg:"der Morgen",src:"the morning / tomorrow",pos:"noun",gender:"m",note:"Masculine. Morgen = morning AND tomorrow!",example:"A: Guten Morgen!\nB: Morgen habe ich frei.",exampleSrc:"A: Good morning!\nB: Tomorrow I'm off.",funFact:"'Morgen Morgen' = tomorrow morning. Germans find this funny too."},
{type:"teach",trg:"die Nacht",src:"the night",pos:"noun",gender:"f",note:"Feminine. 'Gute Nacht' = good night.",example:"A: Gute Nacht!\nB: Schlaf gut!",exampleSrc:"A: Good night!\nB: Sleep well!",funFact:"Nacht is always feminine, like 'la nuit' in French. 'Heute Nacht' = tonight."},
{type:"teach",trg:"die Woche",src:"the week",pos:"noun",gender:"f",note:"Feminine. Plural: die Wochen.",example:"A: Wie war deine Woche?\nB: Gut, aber stressig.",exampleSrc:"A: How was your week?\nB: Good, but stressful.",funFact:"From Old German 'wehsel' (change/turn). A week = one turn of days."},
{type:"teach",trg:"das Wochenende",src:"the weekend",pos:"noun",gender:"n",note:"COMPOUND: Wochen (week) + Ende (end).\nNeuter. Compound: Woche + Ende.",example:"A: Was machst du am Wochenende?\nB: Ich gehe spazieren.",exampleSrc:"A: What are you doing on the weekend?\nB: I'm going for a walk.",funFact:"die Woche + das Ende = das Wochenende. Gender of the LAST word wins."},
{type:"match",pairs:[{trg:"der Morgen",src:"the morning / tomorrow"},{trg:"die Nacht",src:"the night"},{trg:"die Woche",src:"the week"},{trg:"das Wochenende",src:"the weekend"}]},
{type:"teach",trg:"die Uhr",src:"the clock / o'clock",pos:"noun",gender:"f",note:"Feminine. Double meaning: clock AND o'clock.",example:"A: Wie viel Uhr ist es?\nB: Es ist drei Uhr.",exampleSrc:"A: What time is it?\nB: It is three o'clock.",funFact:"'Uhr' means both 'clock' and 'o'clock.' 'Die Uhr ist kaputt' AND 'Es ist drei Uhr.'"},
{type:"teach",trg:"die Minute / die Sekunde",src:"minute / second",pos:"noun",gender:"f",note:"Both feminine. From Latin. Nearly identical to English.",example:"A: Noch eine Minute!\nB: Sekunde mal!",exampleSrc:"A: One more minute!\nB: Just a second!",funFact:"'Sekunde mal!' = Just a second! Very common in everyday speech."},
{type:"mc",q:"'Morgen' hat zwei Bedeutungen. Welche?",opts:["Morgen und morgen","Abend und Nacht","Tag und Woche","Montag und Dienstag"],ans:"Morgen und morgen",hint:"This word means both 'morning' and 'tomorrow' in German."},
{type:"teach",trg:"das Datum / der Kalender",src:"the date / the calendar",pos:"noun",gender:"n",note:"Datum is neuter. Kalender is masculine.",example:"A: Welches Datum ist heute?\nB: Schau im Kalender.",exampleSrc:"A: What date is today?\nB: Check the calendar.",funFact:"Plural of Datum is 'Daten,' which also means 'data.' Context is everything."},
{type:"teach",trg:"gestern",src:"yesterday",pos:"adv",gender:null,note:"Adverb. 'Gestern war alles besser.'",example:"A: Was hast du gestern gemacht?\nB: Gestern war ich müde.",exampleSrc:"A: What did you do yesterday?\nB: Yesterday I was tired.",funFact:"'Gestern war alles besser' = yesterday everything was better. Classic German nostalgia."},
{type:"teach",trg:"spät",src:"late",pos:"adj",gender:null,note:"Adjective/adverb. Opposite of früh. Comparative: später.",example:"A: Es ist spät!\nB: Besser spät als nie.",exampleSrc:"A: It's late!\nB: Better late than never.",funFact:"'Besser spät als nie' = better late than never. Identical proverb!"},
{type:"teach",trg:"gerade",src:"right now / straight",pos:"adv",gender:null,note:"Dual meaning: currently AND straight.",example:"A: Was machst du gerade?\nB: Ich lerne gerade Deutsch.",exampleSrc:"A: What are you doing right now?\nB: I'm learning German right now.",funFact:"'Gerade' also means 'straight.' 'Geradeaus' = straight ahead (from Unit 2!)."},
{type:"fb",s:"Was machst du {1}?",a:["gerade"],opts:["gerade","gestern","morgen","spät"],hint:"Right now. What are you doing at this moment?",sSrc:"What are you doing right now?"},
{type:"teach",trg:"danach / vorher / nachher",src:"after that / before / afterward",pos:"adv",gender:null,note:"Time sequence words. Essential for narrating.",example:"A: Zuerst dusche ich, danach frühstücke ich.\nB: Und nachher?",exampleSrc:"A: First I shower, then I have breakfast.\nB: And after that?",funFact:"Vorher = before. Nachher = afterward. Danach = after that. Three ways to sequence events."},
{type:"teach",trg:"pünktlich",src:"punctual / on time",pos:"adj",gender:null,note:"THE German virtue. Being late is a social crime.",example:"A: Bist du immer pünktlich?\nB: Natürlich! Ich bin deutsch.",exampleSrc:"A: Are you always on time?\nB: Of course! I'm German.",funFact:"Punctuality is sacred in Germany. 5 minutes early = on time. On time = late."},
{type:"tip",title:"Time Expressions",text:"Use um with clock times: um drei Uhr (at 3 o'clock).\nUse am with days: am Montag (on Monday).\n\nStandalone time words need no preposition:\n- gestern (yesterday), heute (today), morgen (tomorrow)\n- gerade (right now), vorher (before), nachher (after), danach (then)\n\nExamples: Es ist drei Uhr. Ich komme um drei."},
{type:"teach",trg:"der Nachmittag / der Vormittag",src:"afternoon / morning (before noon)",pos:"noun",gender:"m",note:"Both masculine. Nach+Mittag / Vor+Mittag.",example:"A: Was machst du am Nachmittag?\nB: Ich lerne Deutsch.",exampleSrc:"A: What are you doing in the afternoon?\nB: I'm learning German.",funFact:"Vormittag = before noon. Nachmittag = after noon. Transparent compounds."},
{type:"teach",trg:"der Schluss",src:"the end / closing time",pos:"noun",gender:"m",note:"Masculine. 'Ladenschluss' = store closing time.",example:"A: Wann ist Schluss?\nB: Um siebzehn Uhr.",exampleSrc:"A: When is closing time?\nB: At 5 PM.",funFact:"'Schluss!' as an exclamation means 'That's it! Enough!' Very final."},
{type:"mc",q:"Es ist 15:00. Es ist ___.",opts:["fünfzehn","drei Uhr","fünf Uhr","dreizehn Uhr"],ans:"drei Uhr",hint:"15:00 in 12-hour = 3 o'clock."},
{type:"fb",s:"Gestern {1} ich sehr müde.",a:["war"],opts:["war","bin","hatte","habe"],hint:"Past tense of sein, first person. I WAS tired.",sSrc:"Yesterday I was very tired."},
{type:"mc",q:"'Ich dusche ___ um sieben Uhr.'",opts:["gestern","danach","morgens","spät"],ans:"morgens",hint:"What time word means 'in the morning' as a habit?"},
{type:"drag_fill",s:"Ich frühstücke {1} sieben {2}.",blanks:{"1":"um","2":"Uhr"},pool:["um","am","Uhr","Morgen","Tag"],hint:"Clock time format: preposition + number + the word for o'clock.",sSrc:"I have breakfast at seven o'clock."},
{type:"mc",q:"'___ hatte ich keinen Hunger.'",opts:["Morgen","Endlich","Gerade","Gestern"],ans:"Gestern",hint:"Which word means 'yesterday'?"}
,
{"type":"mc","q":"Was ist 'die Minute'?","opts":["the minute","the hour","the second","the day"],"ans":"the minute","hint":"Sixty of these make one hour."},
{"type":"fb","s":"Welches {1} haben wir heute?","a":["Datum"],"opts":["Datum","Tag","Monat","Kalender"],"hint":"The specific day, month, and year.","sSrc":"What date is it today?"}]},

// ─── L3: Montag bis Sonntag ───
{id:"deu_r6l3",title:"Montag bis Sonntag",icon:"📅",xp:15,board:true,steps:[
{type:"intro",title:"Montag bis Sonntag",desc:"Days of the week, months, and ordinal numbers. All named after gods, planets, or Latin numbers.",goals:["7 days of the week","First 6 months","Ordinals: erste, zweite, dritte"]},
{type:"teach",trg:"der Montag",src:"Monday",pos:"noun",gender:"m",note:"Masculine. All days are masculine! Mond (moon) + Tag.",example:"A: Am Montag gehe ich arbeiten.\nB: Ich auch!",exampleSrc:"A: On Monday I go to work.\nB: Me too!",funFact:"Moon-day! Same as English Monday (Moon's day). Same Germanic origin."},
{type:"teach",trg:"der Dienstag",src:"Tuesday",pos:"noun",gender:"m",note:"Named after Tyr/Ziu (Norse god).",example:"A: Am Dienstag habe ich Deutsch.\nB: Viel Spaß!",exampleSrc:"A: On Tuesday I have German.\nB: Have fun!",funFact:"English Tuesday = Tyr's day. German Dienstag = Ziu's day. Same god of war and law. (Thor/Donner is the thunder god.)"},
{type:"teach",trg:"der Mittwoch",src:"Wednesday",pos:"noun",gender:"m",note:"Literally 'mid-week.' The ONLY day not named after a god.",example:"A: Mittwoch ist die Mitte der Woche.\nB: Stimmt!",exampleSrc:"A: Wednesday is the middle of the week.\nB: That's right!",funFact:"Mitte + Woche = mid-week. English Wednesday is Woden's day. German went practical."},
{type:"teach",trg:"der Donnerstag",src:"Thursday",pos:"noun",gender:"m",note:"Thunder-day! Donner (thunder) + Tag.",example:"A: Am Donnerstag gehe ich einkaufen.\nB: Ich komme mit!",exampleSrc:"A: On Thursday I go shopping.\nB: I'll come along!",funFact:"Thursday = Thor's day. Donnerstag = Thunder-day. Same thunder god, different names."},
{type:"teach",trg:"der Freitag",src:"Friday",pos:"noun",gender:"m",note:"Named after Freya (goddess of love).",example:"A: Freitag ist mein Lieblingstag!\nB: Meiner auch!",exampleSrc:"A: Friday is my favorite day!\nB: Mine too!",funFact:"Friday = Freya's day. Freitag = Freya's day. Same love goddess."},
{type:"match",pairs:[{trg:"der Dienstag",src:"Tuesday"},{trg:"der Mittwoch",src:"Wednesday"},{trg:"der Donnerstag",src:"Thursday"},{trg:"der Freitag",src:"Friday"}]},
{type:"teach",trg:"der Samstag / der Sonntag",src:"Saturday / Sunday",pos:"noun",gender:"m",note:"Samstag from Hebrew 'Shabbat.' Sonntag = Sun-day.",example:"A: Am Samstag grillen wir.\nB: Und am Sonntag? Ruhetag!",exampleSrc:"A: On Saturday we grill.\nB: And on Sunday? Rest day!",funFact:"Shops are CLOSED on Sundays in Germany. The 'Sonntagsruhe' (Sunday rest) is law."},
{type:"tip",title:"am + Day",text:"All days are masculine, all use 'am' (an + dem):\n\nam Montag = on Monday\nam Dienstag = on Tuesday\n\nNever 'auf Montag' or 'in Montag.'\n'Am' is the ONLY correct preposition for days.",deepDive:{title:"The names behind the days",text:"German day names come from Germanic mythology and astronomy:\n\nMontag = Mond (moon) + Tag\nDienstag = Thing (old Germanic assembly) + Tag\nMittwoch = Mitte der Woche (middle of the week)\nDonnerstag = Donner (thunder, Thor) + Tag\nFreitag = Freya (Norse goddess) + Tag\nSamstag = from Hebrew Shabbat via Greek\nSonntag = Sonne (sun) + Tag\n\nMittwoch is unique: not named after a deity, but literally 'midweek.'"}},
{type:"teach",trg:"der Januar / der Februar / der März",src:"January / February / March",pos:"noun",gender:"m",note:"All months are masculine (der). Same as English roots.",example:"A: Im Januar ist es kalt.\nB: Und im März wird es wärmer.",exampleSrc:"A: In January it's cold.\nB: And in March it gets warmer.",funFact:"Januar (Janus, two-faced god), Februar (purification month), März (Mars, god of war)."},
{type:"teach",trg:"der April / der Mai / der Juni",src:"April / May / June",pos:"noun",gender:"m",note:"All masculine. im + month: 'im April.'",example:"A: Im Mai blühen die Blumen.\nB: Und im Juni scheint die Sonne.",exampleSrc:"A: In May the flowers bloom.\nB: And in June the sun shines.",funFact:"April (opening/spring), Mai (Maia, goddess of growth), Juni (Juno, queen of gods)."},
{type:"teach",trg:"erste / zweite / dritte",src:"first / second / third",pos:"num",gender:null,note:"Ordinal numbers. Irregular for 1st-3rd, regular from 4th.",example:"A: Der erste Januar ist Neujahr.\nB: Und der dritte Oktober?",exampleSrc:"A: The first of January is New Year.\nB: And the third of October?",funFact:"1st/2nd/3rd are irregular (like English). From 4th onward: add -te (vierte, fünfte, sechste)."},
{type:"teach",trg:"seit",src:"since / for (time duration)",pos:"prep",gender:null,note:"Dative preposition! 'Seit drei Wochen' = for three weeks.",example:"A: Seit wann bist du hier?\nB: Seit drei Wochen.",exampleSrc:"A: Since when have you been here?\nB: For three weeks.",funFact:"Always dative. German uses present tense with seit: 'Ich wohne seit drei Wochen hier' (I have been living here for three weeks)."},
{type:"teach",trg:"wichtig / eilig",src:"important / urgent",pos:"adj",gender:null,note:"Two useful adjectives. Essential for office/bureaucracy.",example:"A: Es ist wichtig!\nB: Und eilig! Wir müssen jetzt gehen.",exampleSrc:"A: It's important!\nB: And urgent! We have to go now.",funFact:"'Wichtig' from 'Gewicht' (weight). Important = weighty. 'Ich habe es eilig' = I'm in a hurry."},
{type:"mc",q:"Mittwoch bedeutet:",opts:["Mitte der Woche","Tag des Mondes","Tag des Donners","Tag der Sonne"],ans:"Mitte der Woche",hint:"What does 'Mitt' + 'Woch' combine to mean?"},
{type:"fb",s:"{1} Montag habe ich einen Termin.",a:["Am"],opts:["Am","Im","Um","Seit"],hint:"Days use which preposition contraction?",sSrc:"On Monday I have an appointment."},
{type:"mc",q:"Der ___ Januar ist Neujahr.",opts:["zweite","erste","dritte","vierte"],ans:"erste",hint:"New Year's Day is the 1st."},
{type:"match",pairs:[{trg:"Montag",src:"Monday"},{trg:"Mittwoch",src:"Wednesday"},{trg:"Freitag",src:"Friday"},{trg:"Sonntag",src:"Sunday"},{trg:"Donnerstag",src:"Thursday"}]},
{type:"fb",s:"Ich wohne {1} drei Wochen in Berlin.",a:["seit"],opts:["seit","vor","nach","um"],hint:"Which preposition means 'for' with a continuing duration?",sSrc:"I have been living in Berlin for three weeks."},
{type:"mc",q:"Shops are closed on ___ in Germany.",opts:["Samstag","Freitag","Sonntag","Mittwoch"],ans:"Sonntag",hint:"The Sunday rest is law."}
,
{"type":"mc","q":"Welcher Tag ist 'Dienstag'?","opts":["Tuesday","Monday","Wednesday","Thursday"],"ans":"Tuesday","hint":"The second working day of the week."}]},

// ─── L4: Juli bis Dezember ───
{id:"deu_r6l4",title:"Juli bis Dezember",icon:"🌦️",xp:15,board:true,steps:[
{type:"intro",title:"Juli bis Dezember",desc:"Remaining months, all four seasons, weather vocabulary, and more ordinals. When things happen and what it is like outside.",goals:["6 remaining months","4 seasons with im + season","Weather vocabulary"]},
{type:"teach",trg:"der Juli / der August",src:"July / August",pos:"noun",gender:"m",note:"Both masculine. Named after Roman emperors.",example:"A: Im Juli fahren wir nach Spanien.\nB: Und im August?",exampleSrc:"A: In July we're going to Spain.\nB: And in August?",funFact:"Juli = Julius Caesar. August = Emperor Augustus. August is Germany's main vacation month."},
{type:"teach",trg:"der September / der Oktober / der November / der Dezember",src:"Sept / Oct / Nov / Dec",pos:"noun",gender:"m",note:"All masculine. Nearly identical to English.",example:"A: Im Oktober ist Oktoberfest!\nB: Und im Dezember Weihnachten.",exampleSrc:"A: In October is Oktoberfest!\nB: And in December Christmas.",funFact:"Sept=7, Okt=8, Nov=9, Dez=10 in the old Roman calendar (year started in March)."},
{type:"teach",trg:"der Frühling",src:"spring",pos:"noun",gender:"m",note:"Masculine. Literally 'early-ling.' Früh + -ling.",example:"A: Im Frühling blühen die Blumen.\nB: Ja, alles wird grün!",exampleSrc:"A: In spring the flowers bloom.\nB: Yes, everything turns green!",funFact:"Früh (early) + -ling (suffix) = the early season. Spring arrives!"},
{type:"teach",trg:"der Sommer",src:"summer",pos:"noun",gender:"m",note:"Masculine. Cognate with English 'summer.'",example:"A: Im Sommer grillen wir.\nB: Und im Winter?",exampleSrc:"A: In summer we grill.\nB: And in winter?",funFact:"Same Proto-Germanic root. Identical meaning for 2000+ years."},
{type:"teach",trg:"der Herbst",src:"autumn / fall",pos:"noun",gender:"m",note:"Masculine. Cognate with English 'harvest.'",example:"A: Im Herbst werden die Blätter bunt.\nB: Ja, wunderschön!",exampleSrc:"A: In autumn the leaves turn colorful.\nB: Yes, beautiful!",funFact:"English shifted to 'autumn' (from French). German kept Herbst. Same original meaning: harvest time."},
{type:"match",pairs:[{trg:"der September / der Oktober / der November / der Dezember",src:"Sept / Oct / Nov / Dec"},{trg:"der Frühling",src:"spring"},{trg:"der Sommer",src:"summer"},{trg:"der Herbst",src:"autumn / fall"}]},
{type:"teach",trg:"der Winter",src:"winter",pos:"noun",gender:"m",note:"Masculine. Identical to English.",example:"A: Im Winter ist es kalt.\nB: Ja, minus zehn Grad!",exampleSrc:"A: In winter it's cold.\nB: Yes, minus ten degrees!",funFact:"German winters are serious: -10 degrees C is normal in Bavaria."},
{type:"teach",trg:"das Wetter",src:"the weather",pos:"noun",gender:"n",note:"Neuter. 'Wie ist das Wetter?' = How's the weather?",example:"A: Wie ist das Wetter heute?\nB: Es regnet.",exampleSrc:"A: How is the weather today?\nB: It's raining.",funFact:"Weather is THE small-talk topic in Germany. 'Über das Wetter kann man immer reden.'"},
{type:"teach",trg:"der Regen / regnen",src:"the rain / to rain",pos:"noun",gender:"m",note:"Regen is masculine. Regnen uses 'es': Es regnet.",example:"A: Es regnet schon wieder!\nB: Hast du einen Regenschirm?",exampleSrc:"A: It's raining again!\nB: Do you have an umbrella?",funFact:"Impersonal verb: 'Es regnet.' Only 'es' can rain. You can't say 'Ich regne.'"},
{type:"teach",trg:"der Schnee / die Temperatur",src:"snow / temperature",pos:"noun",gender:"m",note:"Schnee is masculine. Temperatur is feminine.",example:"A: Es schneit! Schnee!\nB: Die Temperatur ist minus fünf.",exampleSrc:"A: It's snowing! Snow!\nB: The temperature is minus five.",funFact:"'Schnee' is cognate with English 'snow.' Germany uses Celsius: 20°C = comfortable."},
{type:"teach",trg:"leider",src:"unfortunately",pos:"adv",gender:null,note:"Adverb. Softens bad news. Germans use it A LOT.",example:"A: Kommst du morgen?\nB: Leider nicht. Ich muss arbeiten.",exampleSrc:"A: Are you coming tomorrow?\nB: Unfortunately not. I have to work.",funFact:"From 'Leid' (suffering). Leider politely softens any disappointment."},
{type:"match",pairs:[{trg:"das Wetter",src:"the weather"},{trg:"der Regen / regnen",src:"the rain / to rain"},{trg:"der Schnee / die Temperatur",src:"snow / temperature"},{trg:"leider",src:"unfortunately"}]},
{type:"teach",trg:"scheinen",src:"to shine / to seem",pos:"verb",gender:null,note:"Dual meaning! 'Die Sonne scheint' AND 'Es scheint gut.'",example:"A: Die Sonne scheint heute.\nB: Endlich!",exampleSrc:"A: The sun is shining today.\nB: Finally!",funFact:"Two completely different meanings: to shine (sun) AND to seem/appear."},
{type:"teach",trg:"vierte / fünfte / sechste",src:"fourth / fifth / sixth",pos:"num",gender:null,note:"Regular from 4th: add -te. Vierte, fünfte, sechste.",example:"A: Der vierte Juli.\nB: Amerikanischer Nationalfeiertag!",exampleSrc:"A: The fourth of July.\nB: American Independence Day!",funFact:"From 4th onward, just add -te to the number. Easy pattern!"},
{type:"tip",title:"im + Month / Season",text:"'Im Januar' (in January)\n'Im Sommer' (in summer)\n\nim = in + dem (dative contraction)\nAll months and seasons are masculine (der).\n\n'Im Winter war es kalt.'\n'Im Mai blühen die Blumen.'",deepDive:{title:"Why 'im' and not 'in'?",text:"'im' is a contraction of in + dem (dative).\n\nSince all months are masculine (der), the dative form is dem.\nin + dem = im.\n\nThis is the same 'im' you use for rooms (im Wohnzimmer) and times (im Sommer).\n\nYou never say 'in Januar' or 'in der Januar.' Always: im Januar."}},
{type:"mc",q:"'Wir fahren ___ Sommer nach Spanien.'",opts:["im","am","um","seit"],ans:"im",hint:"Seasons use im (in + dem)."},
{type:"fb",s:"Es {1} seit drei Tagen.",a:["regnet"],opts:["regnet","schneit","Regen","Wetter"],hint:"The verb for rain, with 'es' as subject.",sSrc:"It rains for three days."},
{type:"mc",q:"Der vierte ___ ist der amerikanische Nationalfeiertag.",opts:["Juni","Juli","August","Mai"],ans:"Juli",hint:"Independence Day: July 4th."},
{type:"drag_fill",s:"Gestern {1} es kalt und ich {2} keinen Regenschirm.",blanks:{"1":"war","2":"hatte"},pool:["war","hatte","ist","habe","bin"],hint:"Past tense of the two most important auxiliary verbs. Think about existence vs. possession.",sSrc:"Yesterday it was cold and I had no umbrella."},
{type:"match",pairs:[{trg:"der Frühling",src:"spring"},{trg:"der Sommer",src:"summer"},{trg:"der Herbst",src:"autumn"},{trg:"der Winter",src:"winter"},{trg:"das Wetter",src:"weather"}]},
{type:"mc",q:"'Leider' means:",opts:["luckily","always","unfortunately","never"],ans:"unfortunately",hint:"From 'Leid' (suffering). Softens bad news."},

{"type":"fb","s":"Die Sonne {1} heute den ganzen Tag.","a":["scheint"],"opts":["scheint","regnet","schneit","weht"],"hint":"What the sun does on a clear day.","sSrc":"The sun shines all day today."}]},

// ─── L5: Der Anruf ───
{id:"deu_r6l5",title:"Der Anruf",icon:"📞",xp:15,board:true,steps:[
{type:"intro",title:"Der Anruf",desc:"Verumius calls the Hausverwaltung about the hot water. Automated menus, hold music, and body parts for the doctor visit.",goals:["Phone and communication vocabulary","More body parts","Imperative in phone context"]},
{type:"teach",trg:"der Anruf / anrufen",src:"the call / to call",pos:"noun",gender:"m",note:"Anruf is masculine. Anrufen is separable: ich rufe an.",example:"A: Ich rufe die Hausverwaltung an.\nB: Gute Idee!",exampleSrc:"A: I'm calling the property management.\nB: Good idea!",funFact:"Separable: 'Ich rufe an.' The 'an' goes to the end. 'Der Anruf' = the call (noun form)."},
{type:"teach",trg:"das Handy",src:"the mobile phone",pos:"noun",gender:"n",note:"Neuter. FALSE FRIEND: not related to English 'handy'!",example:"A: Wo ist mein Handy?\nB: Auf dem Tisch.",exampleSrc:"A: Where is my phone?\nB: On the table.",funFact:"Germans use the English word 'handy' for mobile phones, but English speakers never call phones 'handys.' A Denglisch classic."},
{type:"teach",trg:"das Telefon / telefonieren",src:"telephone / to call",pos:"noun",gender:"n",note:"Telefon is neuter. Telefonieren is NOT separable.",example:"A: Telefonierst du gerade?\nB: Ja, einen Moment bitte.",exampleSrc:"A: Are you on the phone?\nB: Yes, one moment please.",funFact:"'Telefonieren' is inseparable. 'Anrufen' is separable. Both mean 'to call.' Telefonieren is more formal."},
{type:"teach",trg:"die Nachricht / der Brief",src:"message / letter",pos:"noun",gender:"f",note:"Nachricht is feminine. Brief is masculine.",example:"A: Ich habe eine Nachricht bekommen.\nB: Einen Brief oder eine E-Mail?",exampleSrc:"A: I received a message.\nB: A letter or an email?",funFact:"'Nachricht' = message (any kind). 'Brief' = physical letter. 'Die Nachrichten' = the news (always plural)."},
{type:"teach",trg:"die E-Mail / klingeln",src:"the email / to ring",pos:"noun",gender:"f",note:"E-Mail is feminine. Klingeln: das Telefon klingelt.",example:"A: Das Telefon klingelt!\nB: Ich gehe ran.",exampleSrc:"A: The phone is ringing!\nB: I'll answer.",funFact:"'Klingeln' also means doorbell ringing. 'Es klingelt!' = the bell is ringing (phone or door)."},
{type:"mc",q:"'Handy' bedeutet auf Deutsch:",opts:["Mobiltelefon","praktisch","Handtasche","Handcreme"],ans:"Mobiltelefon",hint:"A false friend. In German this word means mobile phone."},
{type:"teach",trg:"das Auge / das Ohr / die Nase",src:"eye / ear / nose",pos:"noun",gender:"n",note:"Auge and Ohr are neuter. Nase is feminine.",example:"A: Ich sehe mit den Augen.\nB: Und ich höre mit den Ohren.",exampleSrc:"A: I see with my eyes.\nB: And I hear with my ears.",funFact:"'Auge' plural is 'Augen.' 'Ohr' plural is 'Ohren.' Both add -en. Easy pattern!"},
{type:"teach",trg:"der Mund / der Zahn / das Haar",src:"mouth / tooth / hair",pos:"noun",gender:"m",note:"Mund and Zahn are masculine. Haar is neuter.",example:"A: Mach den Mund auf!\nB: Der Zahn tut weh.",exampleSrc:"A: Open your mouth!\nB: The tooth hurts.",funFact:"Plural of Zahn: Zähne (umlaut!). 'Zahnarzt' = tooth-doctor = dentist."},
{type:"teach",trg:"das Gesicht / der Zeh",src:"face / toe",pos:"noun",gender:"n",note:"Gesicht is neuter. Zeh is masculine.",example:"A: Mein Gesicht ist rot.\nB: Und mein Zeh tut weh.",exampleSrc:"A: My face is red.\nB: And my toe hurts.",funFact:"Gesicht literally: 'the seen thing.' From 'sehen' (to see). Your face is what people see."},
{type:"mc",q:"'Das Telefon klingelt!' means:",opts:["The phone is broken!","The phone is ringing!","The phone is new!","The phone is expensive!"],ans:"The phone is ringing!",hint:"Klingeln = to ring. Think of the sound: kling-kling!"},
{type:"drag_fill",s:"Ich {1} die Hausverwaltung {2}.",blanks:{"1":"rufe","2":"an"},pool:["rufe","an","telefoniere","klingele","anrufe","bin"],hint:"Separable verb: conjugated stem fills {1}, prefix goes to end at {2}.",sSrc:"I call the property management."},
{type:"mc",q:"'Handy' in German means:",opts:["useful","handbag","mobile phone","hand cream"],ans:"mobile phone",hint:"A German false friend. Nothing to do with the English word 'handy.'"},
{type:"match",pairs:[{trg:"das Auge",src:"eye"},{trg:"das Ohr",src:"ear"},{trg:"die Nase",src:"nose"},{trg:"der Mund",src:"mouth"},{trg:"der Zahn",src:"tooth"}]},
{type:"fb",s:"Ich habe eine {1} von der Hausverwaltung bekommen.",a:["Nachricht"],opts:["Nachricht","Brief","Anruf","Handy"],hint:"A message. Could be email, text, or voicemail.",sSrc:"I received a message from the property management."},
{type:"mc",q:"'Drücken Sie die Eins!' is an example of:",opts:["a simple past tense verb","modal verb","reflexive verb","imperative"],ans:"imperative",hint:"A formal command form. What grammar structure is this?"},
{type:"drag_fill",s:"Mein {1} tut weh und meine {2} sind rot.",blanks:{"1":"Kopf","2":"Augen"},pool:["Kopf","Augen","Hand","Fuß","Ohr"],hint:"Head hurts and eyes are red. Body parts from L1 + this lesson.",sSrc:"My head hurts and my eyes are red."},
{type:"mc",q:"Plural of 'der Zahn':",opts:["die Zähne","die Zahne","die Zähnen","die Zahns"],ans:"die Zähne",hint:"Umlaut + -e pattern. Like Stuhl to Stühle."}
]},

// ─── L6: Beim Arzt ───
{id:"deu_r6l6",title:"Beim Arzt",icon:"🏥",xp:15,board:true,steps:[
{type:"intro",title:"Beim Arzt",desc:"Verumius visits the doctor. Health vocabulary, describing symptoms, and modal verbs in medical context.",goals:["Health and illness vocabulary","Describe symptoms","Modal verbs: müssen/sollen at the doctor"]},
{type:"teach",trg:"der Arzt / die Ärztin",src:"the doctor (m/f)",pos:"noun",gender:"m",note:"Masculine/feminine. Plural: die Ärzte.",example:"A: Ich muss zum Arzt.\nB: Was ist los?",exampleSrc:"A: I have to go to the doctor.\nB: What's wrong?",funFact:"'Zum Arzt gehen' is the standard phrase. 'Hausarzt' = family doctor. You need one in Germany."},
{type:"teach",trg:"krank / gesund",src:"sick / healthy",pos:"adj",gender:null,note:"Opposites. 'Ich bin krank' = I am sick.",example:"A: Bist du krank?\nB: Nein, ich bin gesund.",exampleSrc:"A: Are you sick?\nB: No, I'm healthy.",funFact:"'Krankenwagen' = sick-wagon = ambulance. 'Krankenhaus' = sick-house = hospital. German compound logic."},
{type:"teach",trg:"die Krankheit / die Gesundheit",src:"illness / health",pos:"noun",gender:"f",note:"Both feminine. Gesundheit! = the sneeze response.",example:"A: Gesundheit!\nB: Danke!",exampleSrc:"A: Bless you!\nB: Thanks!",funFact:"Germans say 'Gesundheit!' when someone sneezes. It literally means 'Health!' English borrowed it directly."},
{type:"teach",trg:"das Medikament / die Tablette",src:"medicine / pill",pos:"noun",gender:"n",note:"Medikament is neuter. Tablette is feminine.",example:"A: Nehmen Sie dieses Medikament.\nB: Wie oft?",exampleSrc:"A: Take this medicine.\nB: How often?",funFact:"'Rezept' in German means BOTH 'recipe' (cooking) AND 'prescription' (medical). Context!"},
{type:"teach",trg:"der Schmerz / die Erkältung",src:"pain / cold (illness)",pos:"noun",gender:"m",note:"Schmerz is masculine. Erkältung is feminine.",example:"A: Ich habe Schmerzen.\nB: Wo genau?",exampleSrc:"A: I'm in pain.\nB: Where exactly?",funFact:"Plural 'Schmerzen' is more common. 'Kopfschmerzen' = headache. 'Bauchschmerzen' = stomachache."},
{type:"fb",s:"Ich bin {1}. Ich muss zum Arzt.",a:["krank"],opts:["krank","gesund","müde","hungrig"],hint:"The opposite of healthy. You need a doctor.",sSrc:"I am sick. I must go to the doctor."},
{type:"teach",trg:"das Fieber / der Husten",src:"fever / cough",pos:"noun",gender:"n",note:"Fieber is neuter. Husten is masculine.",example:"A: Ich habe Fieber und Husten.\nB: Gehen Sie zum Arzt!",exampleSrc:"A: I have a fever and cough.\nB: Go to the doctor!",funFact:"'Fieber messen' = to take temperature. Germans use ear thermometers mostly."},
{type:"teach",trg:"weh tun",src:"to hurt",pos:"verb",gender:null,note:"Separable-ish: 'Mein Kopf tut weh.' The weh goes to the end.",example:"A: Was tut weh?\nB: Mein Rücken tut weh.",exampleSrc:"A: What hurts?\nB: My back hurts.",funFact:"Body part + tut weh. 'Mein Arm tut weh. Meine Augen tun weh.' Plural uses 'tun.'"},
{type:"teach",trg:"die Apotheke / das Rezept",src:"pharmacy / prescription (or recipe!)",pos:"noun",gender:"f",note:"Apotheke is feminine. Rezept is neuter.",example:"A: Hier ist das Rezept.\nB: Danke, ich gehe zur Apotheke.",exampleSrc:"A: Here is the prescription.\nB: Thanks, I'll go to the pharmacy.",funFact:"German pharmacies (Apotheke) sell prescription AND non-prescription medicine. No medicine at supermarkets!"},
{type:"mc",q:"'Mein Kopf tut weh' means:",opts:["My head hurts","My head is big","My head is cold","My head is turning"],ans:"My head hurts",hint:"'Weh tun' = to hurt. Which body part is mentioned?"},
{type:"fb",s:"Ich habe {1} und Husten.",a:["Fieber"],opts:["Fieber","Hunger","Durst","Schlaf"],hint:"Fever. A medical symptom, not a daily need.",sSrc:"I have a fever and a cough."},
{type:"mc",q:"'Gesundheit!' is said when someone:",opts:["laughs","sneezes","sleeps","coughs"],ans:"sneezes",hint:"The universal German sneeze response."},
{type:"drag_fill",s:"Sie {1} dieses Medikament drei Mal am Tag {2}.",blanks:{"1":"müssen","2":"nehmen"},pool:["müssen","nehmen","können","trinken","sollen","essen"],hint:"You MUST take this medicine. Modal + infinitive at end.",sSrc:"You must take this medicine three times a day."},
{type:"fb",s:"Ich gehe zur {1}. Ich brauche Medikamente.",a:["Apotheke"],opts:["Apotheke","Kasse","Rezeption","Küche"],hint:"The place that sells medicine.",sSrc:"I am going to the pharmacy. I need medicine."},
{type:"mc",q:"'Krankenhaus' literally means:",opts:["care-house","doctor-house","sick-house","medicine-house"],ans:"sick-house",hint:"Krank (s...) + Haus (h...). German compound logic."},
{type:"match",pairs:[{trg:"der Arzt",src:"doctor"},{trg:"krank",src:"sick"},{trg:"der Schmerz",src:"pain"},{trg:"das Fieber",src:"fever"},{trg:"die Apotheke",src:"pharmacy"}]},
{type:"fb",s:"Der Arzt sagt: 'Sie {1} mehr schlafen.'",a:["sollen"],opts:["sollen","müssen","können","dürfen"],hint:"The doctor gives advice. You SHOULD sleep more.",sSrc:"The doctor says: 'You should sleep more.'"},
{type:"mc",q:"'Rezept' in German means BOTH:",opts:["poison AND medicine","doctor AND nurse","pharmacy AND hospital","prescription AND recipe"],ans:"prescription AND recipe",hint:"Same word, two completely different contexts!"}
]},

// ─── L7: Am Bürgeramt ───
{id:"deu_r6l7",title:"Am Bürgeramt",icon:"🏛️",xp:15,board:true,steps:[
{type:"intro",title:"Am Bürgeramt",desc:"German bureaucracy. Verumius must register at the Bürgeramt. Forms, queue numbers, and the word 'Formular.'",goals:["Office and bureaucracy vocabulary","Fill in forms","Registration process"]},
{type:"teach",trg:"das Formular / das Dokument",src:"form / document",pos:"noun",gender:"n",note:"Both neuter. Essential for German bureaucracy.",example:"A: Bitte füllen Sie das Formular aus.\nB: Welches Dokument brauchen Sie?",exampleSrc:"A: Please fill out the form.\nB: Which document do you need?",funFact:"'Formular ausfüllen' = to fill out a form. Germans love forms. For everything. Every. Single. Thing."},
{type:"teach",trg:"der Termin / der Ausweis",src:"appointment / ID card",pos:"noun",gender:"m",note:"Both masculine. Without a Termin, nothing happens.",example:"A: Haben Sie einen Termin?\nB: Ja, um 14 Uhr. Hier ist mein Ausweis.",exampleSrc:"A: Do you have an appointment?\nB: Yes, at 2 PM. Here is my ID.",funFact:"Many German offices require a Termin booked weeks in advance. Walk-ins? Rarely accepted."},
{type:"teach",trg:"die Anmeldung / die Unterschrift",src:"registration / signature",pos:"noun",gender:"f",note:"Both feminine. You must anmelden (register) when you move.",example:"A: Die Anmeldung ist fertig.\nB: Bitte Ihre Unterschrift hier.",exampleSrc:"A: The registration is done.\nB: Your signature here, please.",funFact:"'Anmeldung' is MANDATORY. You must register your address within 14 days of moving. Fines apply!"},
{type:"teach",trg:"der Vertrag / die Gebühr",src:"contract / fee",pos:"noun",gender:"m",note:"Vertrag is masculine. Gebühr is feminine.",example:"A: Der Vertrag ist unterschrieben.\nB: Und die Gebühr?",exampleSrc:"A: The contract is signed.\nB: And the fee?",funFact:"Germans sign contracts for EVERYTHING: phone, gym, internet. Kündigungsfrist (cancellation period) is real."},
{type:"teach",trg:"die Versicherung",src:"insurance",pos:"noun",gender:"f",note:"COMPOUND: Ver (prefix) + Sicher (safe) + ung (noun suffix).\nFeminine. Health insurance is MANDATORY in Germany.",example:"A: Haben Sie eine Versicherung?\nB: Ja, Krankenversicherung.",exampleSrc:"A: Do you have insurance?\nB: Yes, health insurance.",funFact:"Krankenversicherung (health insurance) is mandatory. Without it, no doctor visit, no registration, no life."},
{type:"mc",q:"Was braucht man für einen Arztbesuch in Deutschland?",opts:["eine Versicherung","einen Arbeitstermin","ein Formular","einen Ausweis"],ans:"eine Versicherung",hint:"Without this, no doctor visit is possible in Germany."},
{type:"teach",trg:"die Verwaltung / der Beamte",src:"administration / official",pos:"noun",gender:"f",note:"Verwaltung is fem. Beamte is masc (adj-noun).",example:"A: Die Verwaltung ist zuständig.\nB: Der Beamte hilft Ihnen.",exampleSrc:"A: The administration is responsible.\nB: The official will help you.",funFact:"German 'Beamte' (civil servants) have legendary job security. Unkündbar (cannot be fired)."},
{type:"teach",trg:"die Halle",src:"the hall, the large room",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Hallen.\nUsed for large indoor spaces: entrance halls, sports halls, train concourses.",example:"A: Wo treffen wir uns?\nB: In der Halle, vor dem Schalter.",exampleSrc:"A: Where do we meet?\nB: In the hall, in front of the counter.",funFact:"Many German public buildings have a Eingangshalle (entrance hall) or Wartehalle (waiting hall). Bahnhofshalle is the main concourse of a train station."},
{type:"mc",q:"'Bitte füllen Sie das Formular aus.' An example of:",opts:["past tense","polite imperative","modal verb","reflexive verb"],ans:"polite imperative",hint:"'Füllen Sie... aus!' uses the formal Sie-form to issue a command. The separable prefix splits off."},
{type:"fb",s:"Haben Sie einen {1}?",a:["Termin"],opts:["Termin","Formular","Vertrag","Ausweis"],hint:"The first question at any German office: do you have an appointment?",sSrc:"Do you have an appointment?"},
{type:"mc",q:"'Anmeldung' is mandatory within ___ days of moving.",opts:["30","7","14","90"],ans:"14",hint:"Two weeks! German bureaucracy waits for no one."},
{type:"match",pairs:[{trg:"das Formular",src:"the form"},{trg:"der Termin",src:"appointment"},{trg:"die Unterschrift",src:"signature"},{trg:"der Vertrag",src:"contract"},{trg:"die Versicherung",src:"insurance"}]},
{type:"drag_fill",s:"Ich {1} das Formular {2} und gebe meine {3}.",blanks:{"1":"fülle","2":"aus","3":"Unterschrift"},pool:["fülle","aus","Unterschrift","Termin","habe","ein"],hint:"Fill out the form (separable: ausfüllen) and give my signature.",sSrc:"I fill the form out and give my signature."},
{type:"fb",s:"Die {1} kostet zwanzig Euro.",a:["Gebühr"],opts:["Gebühr","Versicherung","Anmeldung","Verwaltung"],hint:"The fee. A charge for the service.",sSrc:"The fee costs twenty euros."},
{type:"mc",q:"German civil servants are famous for:",opts:["low salaries overall generally","working weekends","being very fast","legendary job security"],ans:"legendary job security",hint:"Unkündbar = cannot be fired. A German institution."},
{type:"fb",s:"Ohne {1} kann ich nicht zum Arzt gehen.",a:["Versicherung"],opts:["Versicherung","Formular","Termin","Gebühr"],hint:"Without this, no doctor visit in Germany.",sSrc:"Without insurance I cannot go to the doctor."},
{type:"mc",q:"'Hausverwaltung' is a compound of:",opts:["Haus + Verwaltung","Haus + Waltung","Hauser + Verwaltung","Haus + Verwalter"],ans:"Haus + Verwaltung",hint:"House + administration. Property management."}
]},

// ─── L8: Arbeit und Studium ───
{id:"deu_r6l8",title:"Arbeit und Studium",icon:"💼",xp:15,board:true,steps:[
{type:"intro",title:"Arbeit und Studium",desc:"Work, education, and professions. What do you do? How do you describe your job? The most common small-talk topic after weather.",goals:["Work and job vocabulary","Education terms","Describe your profession"]},
{type:"teach",trg:"die Arbeit / arbeiten",src:"work / to work",pos:"noun",gender:"f",note:"Arbeit is feminine. Arbeiten is regular.",example:"A: Wo arbeitest du?\nB: Ich arbeite in einem Büro.",exampleSrc:"A: Where do you work?\nB: I work in an office.",funFact:"'Arbeit macht frei' is a dark phrase from history. In everyday use, 'Arbeit' is neutral: 'Ich gehe zur Arbeit.'"},
{type:"teach",trg:"der Beruf / der Job",src:"profession / job",pos:"noun",gender:"m",note:"Beruf is formal (profession). Job is casual.",example:"A: Was ist dein Beruf?\nB: Ich bin Lehrer.",exampleSrc:"A: What is your profession?\nB: I am a teacher.",funFact:"German drops the article for professions: 'Ich bin Lehrer' (not 'Ich bin EIN Lehrer'). Unique grammar rule."},
{type:"teach",trg:"das Büro / die Firma",src:"office / company",pos:"noun",gender:"n",note:"Büro is neuter. Firma is feminine.",example:"A: Mein Büro ist klein.\nB: Meine Firma ist groß.",exampleSrc:"A: My office is small.\nB: My company is big.",funFact:"'Büro' from French 'bureau.' Germans pronounce it 'bü-ROH.' Many German office words are French loans."},
{type:"teach",trg:"der Lehrer / die Lehrerin",src:"teacher (m/f)",pos:"noun",gender:"m",note:"Always give both forms in German.",example:"A: Mein Lehrer ist streng.\nB: Meine Lehrerin ist nett.",exampleSrc:"A: My teacher (m) is strict.\nB: My teacher (f) is nice.",funFact:"'Lehren' = to teach. 'Lernen' = to learn. Don't mix them up! Lehrer teaches, Lerner learns."},
{type:"teach",trg:"die Schule / die Universität",src:"school / university",pos:"noun",gender:"f",note:"Both feminine. 'Uni' is the casual short form.",example:"A: Gehst du noch zur Schule?\nB: Nein, ich studiere an der Uni.",exampleSrc:"A: Are you still in school?\nB: No, I study at university.",funFact:"'Studieren' in German means studying at university specifically. 'Lernen' is for school or self-study."},
{type:"match",pairs:[{trg:"der Beruf / der Job",src:"profession / job"},{trg:"das Büro / die Firma",src:"office / company"},{trg:"der Lehrer / die Lehrerin",src:"teacher (m/f)"},{trg:"die Schule / die Universität",src:"school / university"}]},
{type:"teach",trg:"studieren / lernen",src:"to study (at uni) / to learn",pos:"verb",gender:null,note:"Studieren = university. Lernen = general learning.",example:"A: Was studierst du?\nB: Ich studiere Medizin.",exampleSrc:"A: What are you studying?\nB: I'm studying medicine.",funFact:"A German 'Student' is ALWAYS a university student. School pupils are 'Schüler.'"},
{type:"teach",trg:"der Chef / die Chefin",src:"boss (m/f)",pos:"noun",gender:"m",note:"From French. Masculine/feminine forms.",example:"A: Mein Chef ist streng.\nB: Meine Chefin ist fair.",exampleSrc:"A: My boss (m) is strict.\nB: My boss (f) is fair.",funFact:"Germans use 'Chef' for boss in everyday speech. In a restaurant, 'der Küchenchef' = head chef."},
{type:"teach",trg:"das Gehalt / der Urlaub",src:"salary / vacation",pos:"noun",gender:"n",note:"Gehalt is neuter. Urlaub is masculine.",example:"A: Wie ist das Gehalt?\nB: Gut. Und 30 Tage Urlaub!",exampleSrc:"A: How is the salary?\nB: Good. And 30 days vacation!",funFact:"Germany mandates minimum 20 vacation days. Most jobs give 25-30. Plus public holidays. Work-life balance!"},
{type:"mc",q:"'Was ist dein Beruf?' You answer 'I am a teacher':",opts:["Ich bin Lehrer.","Ich bin ein Lehrer.","Ich bin der Lehrer.","Ich habe Lehrer."],ans:"Ich bin Lehrer.",hint:"German drops the article for professions."},
{type:"fb",s:"Ich {1} an der Universität.",a:["studiere"],opts:["studiere","lerne","arbeite","lehre"],hint:"At university, Germans use a different verb than lernen.",sSrc:"I study at the university."},
{type:"mc",q:"Germany mandates a minimum of ___ vacation days.",opts:["10","20","15","5"],ans:"20",hint:"Most jobs give 25-30, but the legal minimum is 20."},
{type:"match",pairs:[{trg:"die Arbeit",src:"work"},{trg:"der Beruf",src:"profession"},{trg:"das Büro",src:"office"},{trg:"die Firma",src:"company"},{trg:"der Urlaub",src:"vacation"}]},
{type:"drag_fill",s:"Mein {1} arbeitet bei einer großen {2} in Berlin.",blanks:{"1":"Chef","2":"Firma"},pool:["Chef","Firma","Büro","Schule","Lehrer","Universität"],hint:"My boss works at a big company in Berlin.",sSrc:"My boss works at a large company in Berlin."},
{type:"fb",s:"Ich bin {1}. Ich lehre Deutsch.",a:["Lehrerin"],opts:["Lehrerin","Schülerin","Studentin","Chefin"],hint:"A teacher (female). Add the feminine suffix to the masculine form.",sSrc:"I am a teacher. I teach German."},
{type:"mc",q:"'Studieren' vs 'lernen':",opts:["studieren = general, lernen = university","both mean the same","studieren = at university, lernen = general learning","studieren = reading, lernen = writing"],ans:"studieren = at university, lernen = general learning",hint:"A German 'Student' is always at a specific institution of higher education."},
{type:"fb",s:"Das {1} ist gut. Dreißig Tage Urlaub!",a:["Gehalt"],opts:["Gehalt","Urlaub","Büro","Beruf"],hint:"The salary. Your monthly payment for work.",sSrc:"The salary is good. Thirty days of vacation!"},
{type:"mc",q:"A German Schüler is:",opts:["a university student","a teacher","a professor","a school pupil"],ans:"a school pupil",hint:"In German, the word depends on the learner's level of education."}
]},

// ─── L9: Freizeit und Hobbys ───
{id:"deu_r6l9",title:"Freizeit und Hobbys",icon:"🎨",xp:15,board:true,steps:[
{type:"intro",title:"Freizeit und Hobbys",desc:"What do you do in your free time? Sports, music, travel, and the verb 'gern.' Express what you enjoy.",goals:["Hobby and leisure vocabulary","Sports and activities","Express interests with gern/lieber"]},
{type:"teach",trg:"die Freizeit / das Hobby",src:"free time / hobby",pos:"noun",gender:"f",note:"Freizeit is feminine. Hobby is neuter (borrowed from English).",example:"A: Was machst du in deiner Freizeit?\nB: Mein Hobby ist Schwimmen.",exampleSrc:"A: What do you do in your free time?\nB: My hobby is swimming.",funFact:"'Freizeit' = free + time. A compound noun. Germans take Freizeit seriously: it's when the rules relax."},
{type:"teach",trg:"der Sport / schwimmen",src:"sport / to swim",pos:"noun",gender:"m",note:"Sport is masculine. Schwimmen is irregular (past: schwamm).",example:"A: Treibst du Sport?\nB: Ja, ich schwimme gern.",exampleSrc:"A: Do you do sports?\nB: Yes, I like swimming.",funFact:"'Sport treiben' = to do sports. Treiben literally = to drive/push. Germans push themselves."},
{type:"teach",trg:"laufen / Fahrrad fahren",src:"to run / to ride a bicycle",pos:"verb",gender:null,note:"Laufen: irregular (läuft). Fahrrad fahren: two-word verb.",example:"A: Ich laufe jeden Morgen.\nB: Und ich fahre Fahrrad.",exampleSrc:"A: I run every morning.\nB: And I ride my bicycle.",funFact:"Germany is a cycling nation. Fahrrad = travel-wheel. Dedicated bike lanes everywhere."},
{type:"teach",trg:"spielen / tanzen",src:"to play / to dance",pos:"verb",gender:null,note:"Both regular. Spielen works for sports, instruments, and games.",example:"A: Spielst du gern?\nB: Nein, ich tanze lieber.",exampleSrc:"A: Do you like to play?\nB: No, I prefer dancing.",funFact:"'Spielen' covers everything: Fußball spielen, Gitarre spielen, Karten spielen. One verb for all play."},
{type:"fb",s:"Ich {1} gern Fußball.",a:["spiele"],opts:["spiele","laufe","schwimme","tanze"],hint:"The verb for playing sports and games.",sSrc:"I like to play soccer."},
{type:"teach",trg:"lesen / singen",src:"to read / to sing",pos:"verb",gender:null,note:"Lesen: irregular (liest). Singen: irregular (sang).",example:"A: Ich lese gern Bücher.\nB: Und ich singe gern.",exampleSrc:"A: I like reading books.\nB: And I like singing.",funFact:"'Lesen' has a vowel change: du liest, er liest. Same pattern as essen (isst)."},
{type:"teach",trg:"reisen / das Reisen",src:"to travel / travel",pos:"verb",gender:null,note:"Regular verb. 'Das Reisen' = travel as noun.",example:"A: Ich reise gern.\nB: Wohin reist du?",exampleSrc:"A: I like traveling.\nB: Where do you travel?",funFact:"Germans are the world's biggest travelers. 'Fernweh' = far-sickness = wanderlust. The opposite of Heimweh (homesickness)."},
{type:"teach",trg:"die Musik / das Konzert",src:"music / concert",pos:"noun",gender:"f",note:"Musik is feminine. Konzert is neuter.",example:"A: Ich höre gern Musik.\nB: Gehen wir ins Konzert?",exampleSrc:"A: I like listening to music.\nB: Shall we go to the concert?",funFact:"Germany has more orchestras than any other country. Classical music is serious business."},
{type:"teach",trg:"das Kino / das Theater",src:"cinema / theater",pos:"noun",gender:"n",note:"Both neuter. 'Ins Kino gehen' = to go to the movies.",example:"A: Gehen wir ins Kino?\nB: Oder ins Theater?",exampleSrc:"A: Shall we go to the cinema?\nB: Or to the theater?",funFact:"German cinemas often show films in original language with subtitles (OmU = Original mit Untertiteln)."},
{type:"teach",trg:"malen / fotografieren",src:"to paint / to photograph",pos:"verb",gender:null,note:"Both regular. Creative hobbies.",example:"A: Ich male gern.\nB: Und ich fotografiere gern.",exampleSrc:"A: I like painting.\nB: And I like photographing.",funFact:"'Malen' = to paint (art). 'Streichen' = to paint (walls). Different verbs for different painting!"},
{type:"mc",q:"'Treibst du Sport?' means:",opts:["Do you do sports?","Do you drive sports?","Do you push sports?","Do you like sports?"],ans:"Do you do sports?",hint:"This is a fixed verb-noun collocation. 'Treiben' pairs with a physical activity noun."},
{type:"fb",s:"Ich {1} gern Bücher.",a:["lese"],opts:["lese","singe","spiele","tanze"],hint:"What do you do with books? Read them.",sSrc:"I read books with pleasure."},
{type:"mc",q:"'Fernweh' means:",opts:["a deep homesickness","wanderlust / longing for far places","a strong fear of travel","jet lag after flying far"],ans:"wanderlust / longing for far places",hint:"Fern (f...) + Weh (ache). The opposite of Heimweh."},
{type:"match",pairs:[{trg:"schwimmen",src:"to swim"},{trg:"laufen",src:"to run"},{trg:"spielen",src:"to play"},{trg:"lesen",src:"to read"},{trg:"reisen",src:"to travel"}]},
{type:"drag_fill",s:"Ich {1} gern Fußball, aber ich {2} lieber Fahrrad.",blanks:{"1":"spiele","2":"fahre"},pool:["spiele","fahre","laufe","schwimme","tanze","singe"],hint:"I like playing soccer, but I prefer cycling.",sSrc:"I like to play soccer, but I prefer to ride my bicycle."},
{type:"fb",s:"Gehen wir heute Abend ins {1}?",a:["Kino"],opts:["Kino","Büro","Krankenhaus","Bürgeramt"],hint:"The place where you watch films.",sSrc:"Shall we go to the cinema tonight?"},
{type:"mc",q:"'Spielen' can be used for:",opts:["only outdoor sports","only musical instruments playing","sports, instruments, and games","only children's playground games"],ans:"sports, instruments, and games",hint:"Fußball spielen, Gitarre spielen, Karten spielen. Universal play verb."},
{type:"fb",s:"Mein Hobby ist {1}. Ich reise jedes Jahr.",a:["Reisen"],opts:["Reisen","Lesen","Kochen","Tanzen"],hint:"Travel as a hobby. The noun form.",sSrc:"My hobby is traveling. I travel every year."}]},

// ─── L10: Ein Fest planen ───
{id:"deu_r6l10",title:"Ein Fest planen",icon:"🎉",xp:15,board:true,steps:[
{type:"intro",title:"Ein Fest planen",desc:"Verumius plans a small party. Invitations, food, drinks, and putting all vocabulary together. Cultural event: the German Einweihungsfeier (housewarming).",goals:["Party and event vocabulary","Combine food, time, and place words","Plan and describe an event"]},
{type:"teach",trg:"die Feier / die Party",src:"celebration / party",pos:"noun",gender:"f",note:"Feier is formal, Party is casual. Both feminine.",example:"A: Wir machen eine Feier!\nB: Eine Party? Super!",exampleSrc:"A: We're having a celebration!\nB: A party? Great!",funFact:"'Einweihungsfeier' = housewarming party. Germans bring bread and salt as traditional gifts."},
{type:"teach",trg:"die Einladung / einladen",src:"invitation / to invite",pos:"noun",gender:"f",note:"Einladung is feminine. Einladen is separable: ich lade ein.",example:"A: Ich lade Lukas ein.\nB: Und Hildi?",exampleSrc:"A: I'm inviting Lukas.\nB: And Hildi?",funFact:"Separable: 'Ich lade dich ein!' The 'ein' goes to the end. With modals: 'Ich möchte dich einladen.'"},
{type:"teach",trg:"das Geschenk / schenken",src:"gift / to give (as gift)",pos:"noun",gender:"n",note:"Geschenk is neuter. Schenken is regular.",example:"A: Was schenkst du?\nB: Ich schenke Wein.",exampleSrc:"A: What are you giving?\nB: I'm giving wine.",funFact:"'Schenken' = to give as a gift. 'Geben' = to give in general. Gifts are serious in Germany."},
{type:"teach",trg:"feiern / sich freuen",src:"to celebrate / to be happy/look forward to",pos:"verb",gender:null,note:"Feiern is regular. Sich freuen auf = look forward to.",example:"A: Wir feiern am Samstag!\nB: Ich freue mich!",exampleSrc:"A: We're celebrating on Saturday!\nB: I'm looking forward to it!",funFact:"'Sich freuen auf' = look forward to (future). 'Sich freuen über' = be happy about (present). Preposition matters!"},
{type:"teach",trg:"der Gast / die Gäste",src:"guest / guests",pos:"noun",gender:"m",note:"Masculine. Plural: Gäste (umlaut!).",example:"A: Wie viele Gäste kommen?\nB: Zehn Gäste.",exampleSrc:"A: How many guests are coming?\nB: Ten guests.",funFact:"'Gastfreundschaft' = guest-friendship = hospitality. A German virtue. Guests get the best treatment."},
{type:"match",pairs:[{trg:"die Einladung / einladen",src:"invitation / to invite"},{trg:"das Geschenk / schenken",src:"gift / to give (as gift)"},{trg:"feiern / sich freuen",src:"to celebrate / to be happy/look forward to"},{trg:"der Gast / die Gäste",src:"guest / guests"}]},
{type:"teach",trg:"bringen / holen",src:"to bring / to fetch",pos:"verb",gender:null,note:"Bringen: irregular. Holen: regular.",example:"A: Ich bringe Kuchen.\nB: Und ich hole Getränke.",exampleSrc:"A: I'll bring cake.\nB: And I'll get drinks.",funFact:"'Bringen' = bring (towards here). 'Holen' = fetch/go get (away and back). Direction matters."},
{type:"mc",q:"'Einweihungsfeier' is a:",opts:["housewarming party","office party","birthday party","a big wedding party"],ans:"housewarming party",hint:"Ein+weih+ung = dedication/consecration. Feier = celebration. For a new home."},
{type:"drag_fill",s:"Ich {1} Lukas zur Party {2}.",blanks:{"1":"lade","2":"ein"},pool:["lade","ein","bringe","hole","einlade","schenke"],hint:"Separable verb splits: conjugated stem in {1}, prefix goes to end at {2}.",sSrc:"I invite Lukas to the party."},
{type:"mc",q:"Traditional German housewarming gifts are:",opts:["flowers and wine","bread and salt","money and cards","books and music"],ans:"bread and salt",hint:"Brot und Salz. So the house never lacks food."},
{type:"drag_fill",s:"Wir {1} am Samstag und ich {2} mich sehr!",blanks:{"1":"feiern","2":"freue"},pool:["feiern","freue","bringe","lade","hole","schenke"],hint:"We celebrate on Saturday and I'm looking forward to it!",sSrc:"We celebrate on Saturday and I am very excited!"},
{type:"fb",s:"Wie viele {1} kommen zur Party?",a:["Gäste"],opts:["Gäste","Geschenke","Einladungen","Feiern"],hint:"How many people are invited? The guests.",sSrc:"How many guests are coming to the party?"},
{type:"mc",q:"'Sich freuen auf' means:",opts:["to run away from","to argue about something","to look forward to","to be afraid of"],ans:"to look forward to",hint:"Freuen = to be happy. Auf = towards (future). Happy about something coming."},
{type:"match",pairs:[{trg:"die Feier",src:"celebration"},{trg:"die Einladung",src:"invitation"},{trg:"das Geschenk",src:"gift"},{trg:"der Gast",src:"guest"},{trg:"feiern",src:"to celebrate"}]},
{type:"drag_fill",s:"Ich {1} Kuchen und Lukas {2} Getränke.",blanks:{"1":"bringe","2":"holt"},pool:["bringe","holt","lade","schenke","feiere","hole"],hint:"I bring cake (towards here). Lukas fetches drinks (goes to get them).",sSrc:"I bring cake and Lukas fetches drinks."},
{type:"fb",s:"Was {1} du Verumius zur Einweihungsfeier?",a:["schenkst"],opts:["schenkst","bringst","holst","kaufst"],hint:"What do you GIVE as a gift?",sSrc:"What do you give Verumius for the housewarming?"}]},

// ─── L11: Hildis Tee ───
{id:"deu_r6l11",title:"Hildis Tee",icon:"🍵",xp:15,board:true,steps:[
{type:"intro",title:"Hildis Tee",desc:"Story climax. Verumius is invited to Hildi's apartment for the first time. Hot water is back. Hildi makes tea. A real conversation happens.",goals:["Review all Unit 6 vocabulary in story context","Emotional vocabulary","Hildi's character revelation"]},
{type:"mc",q:"'Das heiße Wasser funktioniert wieder.' Hildi fixed:",opts:["the hot water","the toilet","the cold water","the shower"],ans:"the hot water",hint:"'Heiß' is the opposite of 'kalt.' Something Hildi finally fixed."},
{type:"fb",s:"Möchten Sie einen Tee {1} mir?",a:["bei"],opts:["bei","mit","von","zu dunkel"],hint:"At my place. Which dative preposition means 'at someone's place'?",sSrc:"Would you like a tea at my place?"},
{type:"mc",q:"'Seit einem Monat' uses which case after seit?",opts:["nominative","dative","genitive","accusative"],ans:"dative",hint:"The magic 7 prepositions (aus, bei, mit, nach, seit, von, zu) all require which case?"},
{type:"fb",s:"Am Anfang {1} alles schwer.",a:["ist"],opts:["ist","war","hat","wird"],hint:"In the beginning, everything IS hard. Present tense statement.",sSrc:"In the beginning, everything is hard."},
{type:"mc",q:"The Hausordnung has:",opts:["20 full pages","3 pages","14 pages","7 pages"],ans:"14 pages",hint:"Vierzehn Seiten. Hildi wrote it all herself."},
{type:"fb",s:"Werner {1}: 'Du kannst ein Buch schreiben!'",a:["lacht"],opts:["lacht","schreibt","liest","schläft"],hint:"Werner's reaction to the 14-page Hausordnung. He found it funny.",sSrc:"Werner laughs: 'You can write a book!'"},
{type:"mc",q:"What does Hildi offer Verumius?",opts:["A key to her apartment","A copy of the Hausordnung","A job at the Hausverwaltung","Permission to use her first name"],ans:"Permission to use her first name",hint:"'Sie können Hildi sagen.' From formal to personal. A breakthrough."},
{type:"drag_fill",s:"Hildi wohnt {1} fünf Jahren alleine. Ihr Mann Werner ist {2} fünf Jahren nicht mehr da.",blanks:{"1":"seit","2":"seit"},pool:["seit","vor","nach","bis","um"],hint:"For five years. Both blanks use the same dative preposition for duration.",sSrc:"Hildi has lived alone for five years. Her husband Werner has been gone for five years."},
{type:"teach",trg:"die Ruhezeit",src:"the quiet hours",pos:"noun",gender:"f",note:"Feminine. Ruhe (quiet) + Zeit (time). Mandatory silence periods.",example:"A: Ab wann gilt die Ruhezeit?\nB: Ab 22 Uhr. Kein Lärm mehr.",exampleSrc:"A: From when do quiet hours apply?\nB: From 10 PM. No more noise.",funFact:"German quiet hours (Ruhezeiten) are law: typically 22:00-06:00 at night and 13:00-15:00 midday. Violating them earns a complaint from your Nachbar. Hildi enforces hers strictly."},
{type:"match",pairs:[{trg:"die Ruhezeit",src:"quiet hours"},{trg:"der Durchbruch",src:"breakthrough"},{trg:"der Tee",src:"tea"},{trg:"die Reparatur",src:"repair"},{trg:"der Anfang",src:"beginning"}]},
{type:"fb",s:"Es {1} mir hier in Deutschland.",a:["gefällt"],opts:["gefällt","schmeckt","ist","hat"],hint:"I like it here. The thing pleases ME. Dative verb.",sSrc:"It pleases me here in Germany."},
{type:"mc",q:"This lesson's emotional arc shows Hildi as:",opts:["strict but caring, with hidden vulnerability","cold and distant always","only interested in rules","angry about the hot water"],ans:"strict but caring, with hidden vulnerability",hint:"The Hausordnung, the tea, the first-name offer. Layers."},
{type:"tip",title:"A1 Complete: Verumius Has a Home",text:"Unit 6 is the end of A1.\n\nVerumius now has:\n1. An apartment (with a 14-page Hausordnung)\n2. A friend (Lukas)\n3. A landlady who is becoming a friend (Hildi)\n4. Hot water (finally)\n5. All the German he needs to survive\n\nBut A1 is just survival.\nA2 is where real communication begins."}
]},

// ─── L12: Alles auf Deutsch ───
{id:"deu_r6l12",title:"Alles auf Deutsch",icon:"🏆",xp:25,board:true,steps:[
{type:"intro",title:"Alles auf Deutsch",desc:"Comprehensive Unit 6 review. All vocabulary domains, all grammar, all communicative functions. Prove you can handle daily life in Germany.",goals:["Full Unit 6 vocabulary review","All grammar constructs tested","A1 mastery demonstrated"]},
{type:"mc",q:"'Ich ___ jeden Morgen um sieben Uhr.'",opts:["dusche","schlafe","einschlafe","wecke"],ans:"dusche",hint:"Morning hygiene routine. What do you do at 7 AM?"},
{type:"fb",s:"Gestern {1} das Wasser kalt.",a:["war"],opts:["war","ist","hatte","hat"],hint:"Past tense of sein. Yesterday the water WAS cold.",sSrc:"Yesterday the water was cold."},
{type:"mc",q:"'Am ___ gehe ich zum Arzt.'",opts:["Uhr","Montag","Januar","Sommer"],ans:"Montag",hint:"am + day of the week. Not month, season, or time."},
{type:"drag_fill",s:"Ich habe {1} acht Uhr einen {2} beim Arzt.",blanks:{"1":"um","2":"Termin"},pool:["um","am","Termin","Formular","im","Vertrag"],hint:"AT 8 o'clock (um + time). An appointment.",sSrc:"I have an appointment at eight o'clock at the doctor."},
{type:"fb",s:"Im {1} blühen die Blumen.",a:["Frühling"],opts:["Frühling","Winter","Herbst","Dezember"],hint:"Which season brings flowers?",sSrc:"In spring the flowers bloom."},
{type:"mc",q:"'Mein Kopf tut weh' means:",opts:["My head is big","My head is cold","My head hurts","My head is turning"],ans:"My head hurts",hint:"Weh tun = to hurt."},
{type:"drag_fill",s:"Ich {1} die Hausverwaltung {2} und sage: 'Kein heißes Wasser {3} zwei Tagen!'",blanks:{"1":"rufe","2":"an","3":"seit"},pool:["rufe","an","seit","habe","ein","vor"],hint:"First two blanks form a separable verb meaning 'to phone.' Third blank: a preposition that expresses duration from a past starting point.",sSrc:"I call the property management and say: 'No hot water for two days!'"},
{type:"fb",s:"Bitte füllen Sie das {1} aus.",a:["Formular"],opts:["Formular","Dokument","Vertrag","Ausweis"],hint:"The form. You fill it out at every German office.",sSrc:"Please fill out the form."},
{type:"mc",q:"Was ist dein Beruf? 'Ich bin ___.'",opts:["eine Lehrerin","die Lehrerin","Lehrerinnen","Lehrerin"],ans:"Lehrerin",hint:"German drops the article for professions!"},
{type:"drag_fill",s:"Ich {1} gern Fußball und {2} gern Bücher.",blanks:{"1":"spiele","2":"lese"},pool:["spiele","lese","tanze","schwimme","singe","male"],hint:"Play soccer and read books. Two hobbies.",sSrc:"I like to play soccer and like to read books."},
{type:"drag_fill",s:"Ich {1} Lukas zur Einweihungsfeier {2}.",blanks:{"1":"lade","2":"ein"},pool:["lade","ein","bringe","hole","schenke","feiere"],hint:"Separable verb splits: conjugated stem in {1}, prefix goes to end at {2}.",sSrc:"I invite Lukas to the housewarming party."},
{type:"mc",q:"Traditional German housewarming gifts:",opts:["bread and salt","books and music","flowers and wine","money and cards"],ans:"bread and salt",hint:"So the house never lacks food."},
{type:"match",pairs:[{trg:"der Arzt",src:"doctor"},{trg:"das Formular",src:"form"},{trg:"die Versicherung",src:"insurance"},{trg:"der Termin",src:"appointment"},{trg:"die Feier",src:"celebration"}]},
{type:"drag_fill",s:"Seit {1} Monat wohne ich in Berlin und arbeite bei {2} Firma.",blanks:{"1":"einem","2":"einer"},pool:["einem","einer","einen","ein","eine","dem"],hint:"Seit + dative. Bei + dative.",sSrc:"For a month I have been living in Berlin and working at a company."},
{type:"mc",q:"Hildi says 'Sie können Hildi sagen.' This means:",opts:["Call me tomorrow","Use my first name","Say hello to Hildi","Read the Hausordnung"],ans:"Use my first name",hint:"A shift from formal to personal. She invites informality by sharing something."},
{type:"fb",s:"Es {1} mir sehr gut in Deutschland.",a:["gefällt"],opts:["gefällt","schmeckt","ist","hat"],hint:"I like it here. Gefallen + dative.",sSrc:"It pleases me very well in Germany."},
{type:"drag_fill",s:"Am {1} gehe ich zum Arzt, im {2} fahre ich nach Spanien, und um {3} Uhr fange ich an.",blanks:{"1":"Montag","2":"Sommer","3":"neun"},pool:["Montag","Sommer","neun","Januar","Winter","drei"],hint:"am + day, im + season, um + time. Three time expressions.",sSrc:"On Monday I go to the doctor, in summer I travel to Spain, and at nine o'clock I start."},
{type:"mc",q:"The first chapter is complete. Verumius can now:",opts:["Discuss philosophy in German","Write academic papers","Survive daily life in Germany","Translate poetry"],ans:"Survive daily life in Germany",hint:"This chapter covered greetings, numbers, food, and basic directions. What can you do now?"}]},

{id:"deu_r6l13",title:"Arbeit und Bildung",icon:"🎓",xp:15,board:true,steps:[
{type:"intro",title:"Arbeit und Bildung",desc:"Work and education vocabulary: jobs, studies, and the workplace.",goals:["Learn 20 words about work and education","Practice using job and study vocabulary in context"]},
{type:"teach",trg:"der Arbeitsplatz",src:"the workplace",pos:"noun",gender:"m",note:"COMPOUND: Arbeit (work) + Platz (place).\nMasculine noun. Plural: die Arbeitsplätze. Compound: Arbeit (work) + Platz (place).",example:"A: Wie ist dein Arbeitsplatz?\nB: Mein Arbeitsplatz ist sehr modern.",exampleSrc:"A: How is your workplace?\nB: My workplace is very modern.",funFact:"Germans value a tidy Arbeitsplatz. Many offices have rules about keeping desks clean before going home."},
{type:"teach",trg:"die Klasse",src:"the class/classroom",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Klassen.",example:"A: In welcher Klasse ist dein Kind?\nB: Mein Kind ist in der dritten Klasse.",exampleSrc:"A: What class is your child in?\nB: My child is in third grade.",funFact:"In Germany, Klasse also means grade level. Erste Klasse on a train means first class."},
{type:"teach",trg:"der Kollege",src:"the colleague (male)",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Kollegen. Female form: die Kollegin.",example:"A: Kennst du meinen Kollegen?\nB: Ja, er arbeitet im zweiten Stock.",exampleSrc:"A: Do you know my colleague?\nB: Yes, he works on the second floor.",funFact:"Germans often say Liebe Kolleginnen und Kollegen to address all colleagues in a meeting."},
{type:"teach",trg:"der Kurs",src:"the course",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Kurse.",example:"A: Welchen Kurs besuchst du?\nB: Ich besuche einen Deutschkurs.",exampleSrc:"A: Which course are you attending?\nB: I am attending a German course.",funFact:"Integrationskurs is the official German integration course for immigrants, covering language and civic knowledge."},
{type:"mc",q:"Was ist ein Kollege?",opts:["ein Arbeitskollege","ein Freund","ein Lehrer","ein strenger Chef"],ans:"ein Arbeitskollege",hint:"Someone you work with at the same company."},
{type:"teach",trg:"die Maschine",src:"the machine",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Maschinen.",example:"A: Was macht diese Maschine?\nB: Diese Maschine druckt Etiketten.",exampleSrc:"A: What does this machine do?\nB: This machine prints labels.",funFact:"Waschmaschine (washing machine) is one of the first compound words German learners encounter."},
{type:"teach",trg:"das Praktikum",src:"the internship",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Praktika. From Latin practicum.",example:"A: Machst du ein Praktikum?\nB: Ja, ich mache ein Praktikum bei Siemens.",exampleSrc:"A: Are you doing an internship?\nB: Yes, I am doing an internship at Siemens.",funFact:"Praktika are very common in Germany. Many university programs require at least one before graduation."},
{type:"teach",trg:"die Prüfung",src:"the exam",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Prüfungen.",example:"A: Wann ist die Prüfung?\nB: Die Prüfung ist am Freitag.",exampleSrc:"A: When is the exam?\nB: The exam is on Friday.",funFact:"The Goethe-Prüfung is Germany's most recognized language certification, offered worldwide."},
{type:"teach",trg:"der Schüler",src:"the student/pupil (male)",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Schüler. Female form: die Schülerin. Used for school students, not university.",example:"A: Ist er Schüler?\nB: Ja, er ist Schüler am Gymnasium.",exampleSrc:"A: Is he a student?\nB: Yes, he is a student at the Gymnasium.",funFact:"Schüler is only for school pupils. University students are called Studenten."},
{type:"teach",trg:"die Stelle",src:"the position/job",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Stellen. Also means spot or place.",example:"A: Hast du eine neue Stelle?\nB: Ja, ich habe eine Stelle als Lehrer.",exampleSrc:"A: Do you have a new job?\nB: Yes, I have a position as a teacher.",funFact:"Stellenanzeige means job advertisement. Germans often search on portals like StepStone or Indeed."},
{type:"fb",s:"Die {1} ist am Freitag. Ich muss lernen!",a:["Prüfung"],opts:["Prüfung","Stelle","Klasse","Maschine"],hint:"An exam or test at school or university.",sSrc:"The exam is on Friday. I must study!"},
{type:"teach",trg:"der Student",src:"the university student (male)",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Studenten. Female form: die Studentin. Only for university level.",example:"A: Bist du Student?\nB: Ja, ich bin Student an der Universität Berlin.",exampleSrc:"A: Are you a university student?\nB: Yes, I am a student at the University of Berlin.",funFact:"German students pay very low tuition fees compared to the US or UK. Many public universities charge under 300 euros per semester."},
{type:"teach",trg:"das Studium",src:"the studies/degree program",pos:"noun",gender:"n",note:"Neuter noun. No common plural. Refers to university studies as a whole.",example:"A: Wie lange dauert dein Studium?\nB: Mein Studium dauert drei Jahre.",exampleSrc:"A: How long does your degree take?\nB: My degree takes three years.",funFact:"A typical Bachelor Studium in Germany is 6 semesters (3 years), shorter than in many other countries."},
{type:"teach",trg:"der Test",src:"the test",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Tests.",example:"A: Wie war der Test?\nB: Der Test war nicht so schwer.",exampleSrc:"A: How was the test?\nB: The test was not so hard.",funFact:"Germans borrowed Test directly from English. The older German word is Prüfung, which sounds more formal."},
{type:"teach",trg:"der Unterricht",src:"the lesson/instruction",pos:"noun",gender:"m",note:"Masculine noun. Usually no plural. Refers to teaching sessions.",example:"A: Wann beginnt der Unterricht?\nB: Der Unterricht beginnt um acht Uhr.",exampleSrc:"A: When does the lesson start?\nB: The lesson starts at eight o'clock.",funFact:"German school Unterricht typically starts at 7:45 or 8:00, earlier than in many countries."},
{type:"teach",trg:"verdienen",src:"to earn",pos:"verb",gender:null,note:"Regular verb. Ich verdiene, du verdienst, er/sie verdient.",example:"A: Wie viel verdienst du?\nB: Ich verdiene genug.",exampleSrc:"A: How much do you earn?\nB: I earn enough.",funFact:"Asking about salary is considered quite private in Germany. Many people avoid the topic."},
{type:"mc",q:"'Studieren' benutzt man nur für:",opts:["Schüler","Studenten an der Universität","Schulkinder dort","alle Lernenden"],ans:"Studenten an der Universität",hint:"This verb is reserved for university-level education."}
]},
{id:"deu_r6l13b",title:"Arbeit und Bildung (Teil 2)",icon:"🎓",xp:15,board:true,steps:[
{type:"intro",title:"Arbeit und Bildung (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"werden",src:"to become",pos:"verb",gender:null,note:"Irregular verb. Ich werde, du wirst, er/sie wird. Also used as future auxiliary.",example:"A: Was willst du werden?\nB: Ich will Arzt werden.",exampleSrc:"A: What do you want to become?\nB: I want to become a doctor.",funFact:"Werden is one of the most important German verbs. It forms the future tense and the passive voice."},
{type:"teach",trg:"arbeitslos",src:"unemployed",pos:"adj",gender:null,note:"Adjective. Compound: Arbeit (work) + los (without).",example:"A: Ist er noch arbeitslos?\nB: Nein, er hat jetzt eine Stelle.",exampleSrc:"A: Is he still unemployed?\nB: No, he has a job now.",funFact:"The suffix -los means without, like English -less. Arbeitslos, hoffnungslos (hopeless), kostenlos (free of charge)."},
{type:"teach",trg:"selbständig",src:"self-employed/independent",pos:"adj",gender:null,note:"Adjective. Also spelled selbstständig (both accepted).",example:"A: Arbeitest du in einer Firma?\nB: Nein, ich bin selbständig.",exampleSrc:"A: Do you work at a company?\nB: No, I am self-employed.",funFact:"Germany has over 4 million self-employed people. The word comes from selbst (self) + ständig (standing)."},
{type:"teach",trg:"kulturell",src:"cultural",pos:"adj",gender:null,note:"Adjective. Related to die Kultur (culture).",example:"A: Gibt es kulturelle Angebote hier?\nB: Ja, es gibt viele Museen und Theater.",exampleSrc:"A: Are there cultural offerings here?\nB: Yes, there are many museums and theaters.",funFact:"Germany has over 6,000 museums, making it one of the most culturally rich countries in Europe."},
{type:"teach",trg:"normal",src:"normal",pos:"adj",gender:null,note:"Adjective. Same word in English and German, but pronounced with stress on the second syllable: nor-MAL.",example:"A: Ist das normal hier?\nB: Ja, das ist ganz normal.",exampleSrc:"A: Is that normal here?\nB: Yes, that is completely normal.",funFact:"German borrowed normal from Latin normalis. The pronunciation differs: Germans stress the second syllable."},
{type:"match",pairs:[{trg:"arbeitslos",src:"unemployed"},{trg:"selbständig",src:"self-employed/independent"},{trg:"kulturell",src:"cultural"},{trg:"normal",src:"normal"}]},
{type:"teach",trg:"der Doktor",src:"the doctor/PhD",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Doktoren. Academic title and medical professional.",example:"A: Ist sie Doktor?\nB: Ja, sie hat einen Doktor in Physik.",exampleSrc:"A: Is she a doctor?\nB: Yes, she has a PhD in physics.",funFact:"Germans take the Doktor title very seriously. It appears on official IDs and people expect to be addressed as Herr/Frau Doktor."},
{type:"fb",s:"Er ist {1}. Er hat keine Arbeit.",a:["arbeitslos"],opts:["arbeitslos","selbständig","kulturell","normal"],hint:"Without work. The suffix -los means without.",sSrc:"He is unemployed. He has no work."},
{type:"mc",q:"How do you say 'workplace' in German?",opts:["der Arbeitsplatz","das Arbeiten","die Arbeit","der Arbeitsplatz hier"],ans:"der Arbeitsplatz",hint:"It is a compound noun combining work and place."},
{type:"fb",s:"Ich mache ein {1} bei Siemens.",a:"Praktikum",opts:["Praktikum","Prüfung","Studium","Unterricht"],hint:"This is the German word for an internship.",sSrc:"I am doing an internship at Siemens."},
{type:"mc",q:"Which word means 'to become'?",opts:["lernen","werden","verdienen","arbeiten"],ans:"werden",hint:"This irregular verb also helps form the future tense."},
{type:"match",pairs:[{trg:"die Prüfung",src:"the exam"},{trg:"der Schüler",src:"the pupil"},{trg:"die Stelle",src:"the position/job"},{trg:"arbeitslos",src:"unemployed"},{trg:"der Kurs",src:"the course"}]},
{type:"mc",q:"Was bedeutet 'der Doktor'?",opts:["the class/classroom","self-employed/independent","the doctor/PhD","the student/pupil (male)"],ans:"the doctor/PhD",hint:"A Latin loanword (same as English). Both a medical title and an academic degree."}
]},

{id:"deu_r6l14",title:"Stift und Papier",icon:"✏️",xp:15,board:true,steps:[
{type:"intro",title:"Stift und Papier",desc:"Writing, media, and learning materials. From pencils to newspapers.",goals:["Learn 20 words about writing and media","Practice using these words in everyday contexts"]},
{type:"teach",trg:"die Antwort",src:"the answer",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Antworten. Verb: antworten (to answer).",example:"A: Weißt du die Antwort?\nB: Ja, die Antwort ist Berlin.",exampleSrc:"A: Do you know the answer?\nB: Yes, the answer is Berlin.",funFact:"Antwort comes from Old High German antwurti, meaning a response given face to face."},
{type:"teach",trg:"die Anzeige",src:"the advertisement/display",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Anzeigen. Can mean ad, display, or police report.",example:"A: Hast du die Anzeige gelesen?\nB: Ja, sie suchen einen Koch.",exampleSrc:"A: Did you read the advertisement?\nB: Yes, they are looking for a cook.",funFact:"Anzeige can also mean filing a police report. Ich erstatte Anzeige means I am pressing charges."},
{type:"teach",trg:"die Aufgabe",src:"the task/assignment",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Aufgaben. Compound: auf (up) + Gabe (giving).",example:"A: Was ist deine Aufgabe?\nB: Meine Aufgabe ist die Planung.",exampleSrc:"A: What is your task?\nB: My task is the planning.",funFact:"Hausaufgabe means homework, literally home task. German students get plenty of Hausaufgaben."},
{type:"teach",trg:"die Aussage",src:"the statement",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Aussagen. From aus (out) + sagen (to say).",example:"A: Was ist die Aussage des Textes?\nB: Die Aussage ist klar.",exampleSrc:"A: What is the statement of the text?\nB: The statement is clear.",funFact:"In legal contexts, Aussage means testimony. Eine Aussage machen means to make a statement to police."},
{type:"mc",q:"Was ist 'die Aufgabe'?",opts:["ein Auftrag oder Pflicht","ein Fehler","eine Antwort","eine Frage"],ans:"ein Auftrag oder Pflicht",hint:"A task or assignment. Something you have to do."},
{type:"teach",trg:"das Ergebnis",src:"the result",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Ergebnisse.",example:"A: Wie ist das Ergebnis?\nB: Das Ergebnis ist sehr gut.",exampleSrc:"A: How is the result?\nB: The result is very good.",funFact:"Germans love checking Ergebnisse for soccer matches. The Bundesliga results page is one of the most visited sites."},
{type:"teach",trg:"der Fehler",src:"the mistake/error",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Fehler.",example:"A: Habe ich einen Fehler gemacht?\nB: Nein, alles ist richtig.",exampleSrc:"A: Did I make a mistake?\nB: No, everything is correct.",funFact:"Fehler machen means to make mistakes. Germans say Aus Fehlern lernt man: you learn from mistakes."},
{type:"teach",trg:"die Lösung",src:"the solution",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Lösungen. From lösen (to solve).",example:"A: Gibt es eine Lösung?\nB: Ja, ich habe eine Lösung gefunden.",exampleSrc:"A: Is there a solution?\nB: Yes, I found a solution.",funFact:"Lösung also means dissolving in chemistry. Context tells you whether it is a solution to a problem or a liquid solution."},
{type:"teach",trg:"das Bild",src:"the picture/image",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Bilder.",example:"A: Wer hat dieses Bild gemalt?\nB: Das hat mein Sohn gemalt.",exampleSrc:"A: Who painted this picture?\nB: My son painted it.",funFact:"Bildung means education in German, literally forming or building. Same root as Bild (image, formation)."},
{type:"teach",trg:"der Bleistift",src:"the pencil",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Bleistifte. Compound: Blei (lead) + Stift (pen).",example:"A: Hast du einen Bleistift?\nB: Ja, hier ist ein Bleistift.",exampleSrc:"A: Do you have a pencil?\nB: Yes, here is a pencil.",funFact:"Bleistift literally means lead pen, though modern pencils use graphite, not lead."},
{type:"match",pairs:[{trg:"der Fehler",src:"the mistake/error"},{trg:"die Lösung",src:"the solution"},{trg:"das Bild",src:"the picture/image"},{trg:"der Bleistift",src:"the pencil"}]},
{type:"teach",trg:"der Bogen",src:"the sheet (of paper)/form",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Bögen or die Bogen.",example:"A: Ich brauche einen Bogen Papier.\nB: Hier, nimm diesen Bogen.",exampleSrc:"A: I need a sheet of paper.\nB: Here, take this sheet.",funFact:"Bogen also means bow or arch. The Regenbogen (rainbow) is literally a rain arch."},
{type:"fb",s:"Ich habe einen {1} gemacht. Die Antwort war falsch.",a:["Fehler"],opts:["Fehler","Lösung","Ergebnis","Bogen"],hint:"A mistake. Something incorrect.",sSrc:"I made a mistake. The answer was wrong."}
,
{"type":"mc","q":"Was ist 'die Aussage'?","opts":["the statement","the question","the answer","the warning"],"ans":"the statement","hint":"A declaration or claim someone makes."},
{"type":"fb","s":"Schau dir das {1} an!","a":["Bild"],"opts":["Bild","Buch","Lied","Wort"],"hint":"A visual representation, a photo or painting.","sSrc":"Look at the picture!"}]},
{id:"deu_r6l14b",title:"Stift und Papier (Teil 2)",icon:"✏️",xp:15,board:true,steps:[
{type:"intro",title:"Stift und Papier (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"das Buch",src:"the book",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Bücher.",example:"A: Liest du gern Bücher?\nB: Ja, ich lese jeden Abend ein Buch.",exampleSrc:"A: Do you like reading books?\nB: Yes, I read a book every evening.",funFact:"The Frankfurt Book Fair (Frankfurter Buchmesse) is the world's largest book trade fair, held since the 15th century."},
{type:"teach",trg:"der Buchstabe",src:"the letter (of the alphabet)",pos:"noun",gender:"m",note:"COMPOUND: Buch (beech) + Stab (stick/staff).\nMasculine noun. Plural: die Buchstaben. Weak noun: den/dem Buchstaben.",example:"A: Wie viele Buchstaben hat das Alphabet?\nB: Das deutsche Alphabet hat 26 Buchstaben plus Umlaute.",exampleSrc:"A: How many letters does the alphabet have?\nB: The German alphabet has 26 letters plus umlauts.",funFact:"Buchstabe literally comes from Buche (beech tree) + Stab (staff), referring to ancient runes carved into beech wood."},
{type:"teach",trg:"der Kugelschreiber",src:"the ballpoint pen",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Kugelschreiber. Often shortened to Kuli.",example:"A: Kann ich deinen Kugelschreiber haben?\nB: Klar, hier ist mein Kuli.",exampleSrc:"A: Can I have your ballpoint pen?\nB: Sure, here is my pen.",funFact:"Kugelschreiber literally means ball writer. Almost everyone shortens it to Kuli in everyday speech."},
{type:"teach",trg:"das Papier",src:"the paper",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Papiere. Papiere also means documents or ID papers.",example:"A: Haben Sie Ihre Papiere dabei?\nB: Ja, hier ist mein Ausweis.",exampleSrc:"A: Do you have your papers with you?\nB: Yes, here is my ID.",funFact:"Papiere in plural often means identity documents. Ihre Papiere, bitte is what police say when checking IDs."},
{type:"teach",trg:"der Satz",src:"the sentence",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Sätze.",example:"A: Kannst du den Satz wiederholen?\nB: Ja: Ich lerne Deutsch.",exampleSrc:"A: Can you repeat the sentence?\nB: Yes: I am learning German.",funFact:"Satz has many meanings: sentence, set (in tennis), movement (in music), and rate (Zinssatz = interest rate)."},
{type:"mc",q:"'Kugelschreiber' wird oft abgekürzt als:",opts:["Kuli","Schreiber","KS","Kugel"],ans:"Kuli",hint:"The short form of this long compound word for ballpoint pen."},
{type:"teach",trg:"der Text",src:"the text",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Texte.",example:"A: Hast du den Text gelesen?\nB: Ja, der Text war interessant.",exampleSrc:"A: Did you read the text?\nB: Yes, the text was interesting.",funFact:"Text comes from Latin textus meaning woven. A text is a weaving of words."},
{type:"teach",trg:"das Thema",src:"the topic/theme",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Themen. From Greek thema.",example:"A: Was ist das Thema heute?\nB: Das Thema ist Umweltschutz.",exampleSrc:"A: What is the topic today?\nB: The topic is environmental protection.",funFact:"Kein Thema is a casual German way of saying no problem or do not mention it."},
{type:"teach",trg:"das Wort",src:"the word",pos:"noun",gender:"n",note:"Neuter noun. Two plurals: die Wörter (individual words), die Worte (connected speech/sayings).",example:"A: Was bedeutet dieses Wort?\nB: Dieses Wort bedeutet Freundschaft.",exampleSrc:"A: What does this word mean?\nB: This word means friendship.",funFact:"German distinguishes Wörter (individual dictionary words) from Worte (meaningful words in context, like famous last Worte)."},
{type:"teach",trg:"die Zeitung",src:"the newspaper",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Zeitungen. From Zeit (time) + -ung.",example:"A: Liest du die Zeitung?\nB: Ja, ich lese die Zeitung am Morgen.",exampleSrc:"A: Do you read the newspaper?\nB: Yes, I read the newspaper in the morning.",funFact:"Bild-Zeitung (Bild) is Germany's most-read newspaper, known for its bold headlines and tabloid style."},
{type:"teach",trg:"der Film",src:"the film/movie",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Filme.",example:"A: Welchen Film möchtest du sehen?\nB: Ich möchte einen deutschen Film sehen.",exampleSrc:"A: Which movie would you like to see?\nB: I would like to see a German movie.",funFact:"Germany has a strong film industry. The Berlin International Film Festival (Berlinale) is one of the world's top three."},
{type:"fb",s:"Was ist das {1} heute?",a:["Thema"],opts:["Thema","Text","Wort","Satz"],hint:"The topic or subject of discussion.",sSrc:"What is the topic today?"},
{type:"mc",q:"What does 'der Fehler' mean?",opts:["the solution","the mistake","the result","the task"],ans:"the mistake",hint:"Think of something you want to correct."},
{type:"fb",s:"Ich brauche einen {1} und Papier.",a:"Bleistift",opts:["Bleistift","Buchstabe","Bogen","Buch"],hint:"A writing tool made of wood with graphite inside.",sSrc:"I need a pencil and paper."},
{type:"mc",q:"Which word means 'the topic'?",opts:["der Satz","das Wort","das Thema","der Text"],ans:"das Thema",hint:"This neuter noun comes from Greek and means subject of discussion."},
{type:"match",pairs:[{trg:"die Zeitung",src:"the newspaper"},{trg:"das Buch",src:"the book"},{trg:"die Lösung",src:"the solution"},{trg:"die Aufgabe",src:"the task"},{trg:"der Film",src:"the film"}]},
{type:"mc",q:"Was bedeutet 'das Papier'?",opts:["the advertisement/display","the topic/theme","the answer","the paper"],ans:"the paper",hint:"Neuter noun from Latin 'papyrus.' The material you write and print on."}
]},

{id:"deu_r6l15",title:"Am Telefon",icon:"📱",xp:15,board:true,steps:[
{type:"intro",title:"Am Telefon",desc:"Communication, phone, mail, and technology vocabulary for everyday life.",goals:["Learn 18 words about phones, mail, and technology","Practice using communication vocabulary in context"]},
{type:"teach",trg:"der Absender",src:"the sender",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Absender. From ab (away) + senden (to send).",example:"A: Wer ist der Absender?\nB: Der Absender ist mein Bruder.",exampleSrc:"A: Who is the sender?\nB: The sender is my brother.",funFact:"On German letters, the Absender goes in the top left corner, not on the back of the envelope."},
{type:"teach",trg:"der Anrufbeantworter",src:"the answering machine",pos:"noun",gender:"m",note:"COMPOUND: Anruf (call) + Beantworter (answerer).\nMasculine noun. Plural: die Anrufbeantworter. Compound: Anruf (call) + Beantworter (answerer).",example:"A: Hast du meine Nachricht gehört?\nB: Nein, mein Anrufbeantworter war voll.",exampleSrc:"A: Did you hear my message?\nB: No, my answering machine was full.",funFact:"At 19 letters, Anrufbeantworter is a classic example of German compound words. Most people just say AB."},
{type:"teach",trg:"die Briefmarke",src:"the postage stamp",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Briefmarken. Compound: Brief (letter) + Marke (mark/stamp).",example:"A: Ich brauche eine Briefmarke.\nB: Briefmarken gibt es an der Post.",exampleSrc:"A: I need a postage stamp.\nB: You can get stamps at the post office.",funFact:"Collecting Briefmarken (philately) is a beloved hobby in Germany. The first German stamp was the Schwarzer Einser from 1849."},
{type:"teach",trg:"der Empfänger",src:"the recipient",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Empfänger. From empfangen (to receive).",example:"A: Wer ist der Empfänger?\nB: Der Empfänger ist Frau Müller.",exampleSrc:"A: Who is the recipient?\nB: The recipient is Mrs. Müller.",funFact:"On a German envelope, der Empfänger goes in the center. The address format is: name, street + number, postal code + city."},
{type:"teach",trg:"das Fax",src:"the fax",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Faxe. Short for Faksimile.",example:"A: Können Sie mir ein Fax schicken?\nB: Ja, ich schicke das Fax sofort.",exampleSrc:"A: Can you send me a fax?\nB: Yes, I will send the fax right away.",funFact:"Germany still uses fax machines more than most countries. Many offices and government agencies prefer fax over email."},
{type:"match",pairs:[{trg:"der Anrufbeantworter",src:"the answering machine"},{trg:"die Briefmarke",src:"the postage stamp"},{trg:"der Empfänger",src:"the recipient"},{trg:"das Fax",src:"the fax"}]},
{type:"teach",trg:"die Postleitzahl",src:"the postal code",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Postleitzahlen. Abbreviated PLZ.",example:"A: Was ist die Postleitzahl?\nB: Die Postleitzahl ist 10115.",exampleSrc:"A: What is the postal code?\nB: The postal code is 10115.",funFact:"German postal codes have 5 digits. Berlin codes start with 10, Munich with 80, Hamburg with 20."},
{type:"mc",q:"Was steht oben links auf einem deutschen Brief?",opts:["der Absender","der Empfänger","die Briefmarke","die Postleitzahl"],ans:"der Absender",hint:"The person who sends the letter goes in the top left corner."},
{type:"teach",trg:"die Vorwahl",src:"the area code",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Vorwahlen. Compound: vor (before) + Wahl (dialing).",example:"A: Was ist die Vorwahl von Berlin?\nB: Die Vorwahl ist 030.",exampleSrc:"A: What is the area code for Berlin?\nB: The area code is 030.",funFact:"Germany's country code is +49. When calling from abroad, you drop the leading 0 from the Vorwahl."},
{type:"teach",trg:"das Wiederhören",src:"the hearing again",pos:"noun",gender:"n",note:"Neuter noun. Used in Auf Wiederhören (goodbye on the phone).",example:"A: Dann bis morgen. Auf Wiederhören!\nB: Auf Wiederhören!",exampleSrc:"A: Then until tomorrow. Goodbye!\nB: Goodbye!",funFact:"Auf Wiederhören is for phone calls (hearing again). Auf Wiedersehen is for in-person goodbyes (seeing again)."},
{type:"teach",trg:"die CD",src:"the CD",pos:"noun",gender:"f",note:"Feminine noun. Plural: die CDs. Pronounced tsee-dee.",example:"A: Hast du noch CDs?\nB: Ja, ich habe viele alte CDs.",exampleSrc:"A: Do you still have CDs?\nB: Yes, I have many old CDs.",funFact:"Germans pronounce CD as tsee-dee, not see-dee. The letters follow German pronunciation rules."},
{type:"teach",trg:"der Drucker",src:"the printer",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Drucker. From drucken (to print).",example:"A: Funktioniert der Drucker?\nB: Nein, der Drucker ist kaputt.",exampleSrc:"A: Does the printer work?\nB: No, the printer is broken.",funFact:"Drucker also means printer as a profession. Johannes Gutenberg was the most famous Drucker in history."},
{type:"fb",s:"Am Telefon sagt man zum Abschied: Auf {1}!",a:["Wiederhören"],opts:["Wiederhören","Wiedersehen","Morgen","Abend"],hint:"On the phone you say goodbye with hearing, not seeing.",sSrc:"On the phone one says goodbye: Auf Wiederhören!"}
,
{"type":"mc","q":"Was ist 'die CD'?","opts":["the CD","the DVD","the USB","the radio"],"ans":"the CD","hint":"A round disc for storing music or data."}]},
{id:"deu_r6l15b",title:"Am Telefon (Teil 2)",icon:"📱",xp:15,board:true,steps:[
{type:"intro",title:"Am Telefon (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"das Internet",src:"the internet",pos:"noun",gender:"n",note:"Neuter noun. No plural. Always with article: das Internet.",example:"A: Hast du Internet zu Hause?\nB: Ja, aber es ist langsam.",exampleSrc:"A: Do you have internet at home?\nB: Yes, but it is slow.",funFact:"Germany is often teased for slow Internet. The country has been working to expand fiber optic networks."},
{type:"teach",trg:"das Lieblingslied",src:"the favorite song",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Lieblingslieder. Compound: Liebling (favorite) + Lied (song).",example:"A: Was ist dein Lieblingslied?\nB: Mein Lieblingslied ist von den Beatles.",exampleSrc:"A: What is your favorite song?\nB: My favorite song is by the Beatles.",funFact:"Lieblings- is a productive prefix. You can make Lieblingsfilm, Lieblingsbuch, Lieblingsessen for any favorite thing."},
{type:"teach",trg:"das Lied",src:"the song",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Lieder.",example:"A: Kennst du dieses Lied?\nB: Ja, das ist ein altes Volkslied.",exampleSrc:"A: Do you know this song?\nB: Yes, that is an old folk song.",funFact:"Volkslied means folk song. Germany has a rich tradition of Volkslieder, many dating back centuries."},
{type:"teach",trg:"das Gespräch",src:"the conversation",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Gespräche. From sprechen (to speak).",example:"A: Wie war das Gespräch?\nB: Das Gespräch war sehr nett.",exampleSrc:"A: How was the conversation?\nB: The conversation was very nice.",funFact:"Vorstellungsgespräch means job interview, literally an introduction conversation."},
{type:"mc",q:"Was ist ein 'Lieblingslied'?",opts:["das Lied, das man am meisten mag","ein altes Lied","ein Liebeslied","ein langes Lied"],ans:"das Lied, das man am meisten mag",hint:"Lieblings- means favorite. This compound describes the song you love most."},
{type:"teach",trg:"automatisch",src:"automatic",pos:"adj",gender:null,note:"Adjective. Same root as English automatic, from Greek automatos.",example:"A: Ist die Tür automatisch?\nB: Ja, die Tür öffnet sich automatisch.",exampleSrc:"A: Is the door automatic?\nB: Yes, the door opens automatically.",funFact:"German adds -isch to many international words: automatisch, romantisch, fantastisch."},
{type:"teach",trg:"drucken",src:"to print",pos:"verb",gender:null,note:"Regular verb. Ich drucke, du druckst, er/sie druckt. Do not confuse with drücken (to press).",example:"A: Kannst du das drucken?\nB: Ja, ich drucke es sofort.",exampleSrc:"A: Can you print that?\nB: Yes, I will print it right away.",funFact:"Drucken and drücken look alike but differ: drucken = to print, drücken = to press or push."},
{type:"teach",trg:"drücken",src:"to press/push",pos:"verb",gender:null,note:"Regular verb. Ich drücke, du drückst, er/sie drückt. The umlaut distinguishes it from drucken.",example:"A: Welchen Knopf soll ich drücken?\nB: Drück den grünen Knopf.",exampleSrc:"A: Which button should I press?\nB: Press the green button.",funFact:"Ich drücke dir die Daumen means I press my thumbs for you, the German way of saying I am keeping my fingers crossed."},
{type:"teach",trg:"benutzen",src:"to use",pos:"verb",gender:null,note:"Regular verb. Ich benutze, du benutzt, er/sie benutzt. Synonym: verwenden.",example:"A: Kann ich dein Telefon benutzen?\nB: Ja, du kannst es benutzen.",exampleSrc:"A: Can I use your phone?\nB: Yes, you can use it.",funFact:"Benutzen and verwenden both mean to use. Benutzen is more casual, verwenden more formal."},
{type:"fb",s:"{1} den grünen Knopf!",a:["Drück"],opts:["Drück","Druck","Benutz","Schreib"],hint:"Press the button. The verb with umlaut, imperative form.",sSrc:"Press the green button!"},
{type:"mc",q:"What is the German phrase for 'goodbye' on the phone?",opts:["Tschüss","Auf Wiederhören","Bis bald","Auf Wiedersehen (formal)"],ans:"Auf Wiederhören",hint:"This phrase uses the word for hearing, not seeing."},
{type:"fb",s:"Kannst du das bitte {1}? Ich brauche eine Kopie.",a:"drucken",opts:["drucken","drücken","benutzen","schicken"],hint:"This verb means making a paper copy with a machine.",sSrc:"Can you please print that? I need a copy."},
{type:"mc",q:"What does 'der Empfänger' mean?",opts:["the stamp","the area code","the recipient","the sender"],ans:"the recipient",hint:"This person is on the other end of mail delivery."},
{type:"match",pairs:[{trg:"der Absender",src:"the sender"},{trg:"die Briefmarke",src:"the stamp"},{trg:"das Gespräch",src:"the conversation"},{trg:"der Drucker",src:"the printer"},{trg:"das Lied",src:"the song"}]},
{type:"mc",q:"Was bedeutet 'das Internet'?",opts:["to print","the printer","the favorite song","the internet"],ans:"the internet",hint:"Neuter noun. An international loanword, same spelling as English. The global network."},
{type:"fb",s:"Wie sagt man 'the favorite song' auf Deutsch? {1}",a:["das Lieblingslied"],opts:["das Lieblingslied","das Wiederhören","das Fax","das Gespräch"],hint:"A compound: the 'Lieblings-' prefix (favorite) + 'Lied' (song). Neuter noun.",sSrc:"How do you say 'the favorite song' in German?"},
{type:"mc",q:"Was bedeutet 'automatisch'?",opts:["automatic","the sender","to use","the favorite song"],ans:"automatic",hint:"An international adjective from Greek 'automatos.' Nearly identical spelling in English."}
]},

{id:"deu_r6l16",title:"Was machst du so?",icon:"🎬",xp:15,board:true,steps:[
{type:"intro",title:"Was machst du so?",desc:"Daily activities, hobbies, and action verbs for everyday German life.",goals:["Learn 18 essential activity and hobby verbs","Practice separable prefix verbs","Use verbs in everyday conversation"]},
{type:"teach",trg:"anmelden",src:"to register / sign up",pos:"verb",gender:null,note:"Separable: Ich melde mich an. Reflexive with sich.",example:"A: Hast du dich schon angemeldet?\nB: Nein, ich melde mich morgen an.",exampleSrc:"A: Have you already registered?\nB: No, I'll register tomorrow.",funFact:"Germans register for everything: gym, courses, even moving to a new city (Anmeldung)."},
{type:"teach",trg:"ausfüllen",src:"to fill out",pos:"verb",gender:null,note:"Separable: Ich fülle das Formular aus.",example:"A: Kannst du das Formular ausfüllen?\nB: Ja, ich fülle es jetzt aus.",exampleSrc:"A: Can you fill out the form?\nB: Yes, I'll fill it out now.",funFact:"German bureaucracy loves forms. You will ausfüllen many Formulare in your life in Germany."},
{type:"teach",trg:"erlauben",src:"to allow / permit",pos:"verb",gender:null,note:"Not separable. Erlauben Sie? is a polite way to ask permission.",example:"A: Ist Rauchen hier erlaubt?\nB: Nein, das ist nicht erlaubt.",exampleSrc:"A: Is smoking allowed here?\nB: No, that is not allowed.",funFact:"Erlaubnis (permission) comes from erlauben. German laws love the word 'nicht erlaubt'."},
{type:"teach",trg:"erzählen",src:"to tell / narrate",pos:"verb",gender:null,note:"Not separable. Erzähl mir! means Tell me!",example:"A: Erzähl mir von deinem Urlaub!\nB: Es war wunderbar. Ich erzähle dir alles.",exampleSrc:"A: Tell me about your vacation!\nB: It was wonderful. I'll tell you everything.",funFact:"Eine Erzählung is a narrative or story. Germany has a rich tradition of Erzählkunst (narrative art)."},
{type:"teach",trg:"vorstellen",src:"to introduce / imagine",pos:"verb",gender:null,note:"Separable: Ich stelle mich vor (introduce). Ich stelle mir vor (imagine).",example:"A: Kannst du dich bitte vorstellen?\nB: Ja, ich heiße Anna und komme aus Berlin.",exampleSrc:"A: Can you please introduce yourself?\nB: Yes, my name is Anna and I'm from Berlin.",funFact:"Vorstellung means both introduction AND imagination. Also a theater performance!"},
{type:"fb",s:"Ich {1} das Formular jetzt aus.",a:["fülle"],opts:["fülle","gebe","melde","stelle"],hint:"Separable verb meaning to fill out. The prefix goes to the end.",sSrc:"I fill out the form now."},
{type:"teach",trg:"abgeben",src:"to hand in / submit",pos:"verb",gender:null,note:"Separable: Ich gebe die Arbeit ab.",example:"A: Wann gibst du die Hausaufgabe ab?\nB: Ich gebe sie morgen ab.",exampleSrc:"A: When do you hand in the homework?\nB: I'll hand it in tomorrow.",funFact:"At German universities, you abgeben your thesis at a specific office with a timestamp."},
{type:"teach",trg:"anklicken",src:"to click on",pos:"verb",gender:null,note:"Separable: Klick den Link an! Used for computer/phone actions.",example:"A: Was soll ich machen?\nB: Klick einfach den Button an.",exampleSrc:"A: What should I do?\nB: Just click on the button.",funFact:"German tech vocabulary mixes English loans with German prefixes: anklicken, downloaden, uploaden."},
{type:"teach",trg:"ankreuzen",src:"to check / mark with X",pos:"verb",gender:null,note:"Separable: Kreuz die richtige Antwort an.",example:"A: Was muss ich hier machen?\nB: Kreuz bitte die richtige Antwort an.",exampleSrc:"A: What do I have to do here?\nB: Please check the correct answer.",funFact:"In Germany, you mark answers with an X (Kreuz), not a checkmark. The opposite of many countries!"},
{type:"teach",trg:"fehlen",src:"to be missing / absent",pos:"verb",gender:null,note:"Works like gefallen: the missing thing is the subject. Du fehlst mir = I miss you.",example:"A: Wer fehlt heute?\nB: Lisa fehlt. Sie ist krank.",exampleSrc:"A: Who is absent today?\nB: Lisa is absent. She is sick.",funFact:"Du fehlst mir literally means 'You are missing to me.' German expresses missing someone from the other direction."},
{type:"mc",q:"'Du fehlst mir' bedeutet:",opts:["Ich vermisse dich.","Du bist krank.","Du brauchst Hilfe.","Du bist falsch."],ans:"Ich vermisse dich.",hint:"The missing person is the grammatical subject. You are missed by me."}
,
{"type":"fb","s":"Darf ich mich {1}? Ich bin Anna.","a":["vorstellen"],"opts":["vorstellen","verstehen","vergessen","verlassen"],"hint":"What you do when you tell someone your name.","sSrc":"May I introduce myself? I am Anna."}]},
{id:"deu_r6l16b",title:"Was machst du so? (Teil 2)",icon:"🎬",xp:15,board:true,steps:[
{type:"intro",title:"Was machst du so? (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"fernsehen",src:"to watch TV",pos:"verb",gender:null,note:"Separable: Ich sehe fern. Das Fernsehen = television (noun).",example:"A: Was machst du heute Abend?\nB: Ich sehe ein bisschen fern.",exampleSrc:"A: What are you doing tonight?\nB: I'm watching a bit of TV.",funFact:"Fernsehen literally means 'far-seeing.' Germans watch about 3.5 hours of TV per day on average."},
{type:"teach",trg:"gewinnen",src:"to win",pos:"verb",gender:null,note:"Irregular past: gewann, hat gewonnen.",example:"A: Wer hat das Spiel gewonnen?\nB: Deutschland hat drei zu eins gewonnen!",exampleSrc:"A: Who won the game?\nB: Germany won three to one!",funFact:"Der Gewinner (winner) and der Gewinn (prize/profit) both come from gewinnen."},
{type:"teach",trg:"glauben",src:"to believe",pos:"verb",gender:null,note:"Regular verb. Ich glaube (nicht) = I (don't) think so.",example:"A: Kommt er heute?\nB: Ich glaube nicht. Er ist krank.",exampleSrc:"A: Is he coming today?\nB: I don't think so. He is sick.",funFact:"Ich glaube schon (I think so) and Ich glaube nicht (I don't think so) are among the most common German phrases."},
{type:"teach",trg:"kümmern",src:"to care / take care of",pos:"verb",gender:null,note:"Reflexive: sich kümmern um + accusative. Ich kümmere mich darum.",example:"A: Wer kümmert sich um die Kinder?\nB: Ich kümmere mich heute um sie.",exampleSrc:"A: Who takes care of the children?\nB: I'll take care of them today.",funFact:"Kummer means grief or sorrow. Sich kümmern originally meant to worry about something, now it means to take care of it."},
{type:"fb",s:"Ich {1} mich um die Kinder.",a:["kümmere"],opts:["kümmere","glaube","gewinne","lache"],hint:"To take care of someone. Reflexive verb with um.",sSrc:"I take care of the children."},
{type:"teach",trg:"lachen",src:"to laugh",pos:"verb",gender:null,note:"Regular verb. Lach nicht! = Don't laugh!",example:"A: Warum lachst du?\nB: Der Film ist so lustig!",exampleSrc:"A: Why are you laughing?\nB: The movie is so funny!",funFact:"Das Lachen is contagious in any language. Germans even have Lachyoga (laughter yoga) classes."},
{type:"teach",trg:"leben",src:"to live",pos:"verb",gender:null,note:"Regular verb. Means to be alive / to reside. Das Leben = life.",example:"A: Wo lebst du?\nB: Ich lebe in Hamburg.",exampleSrc:"A: Where do you live?\nB: I live in Hamburg.",funFact:"Leben and wohnen both mean 'to live,' but leben is broader (to be alive, to exist) while wohnen is specifically about where you reside."},
{type:"teach",trg:"mitmachen",src:"to participate / join in",pos:"verb",gender:null,note:"Separable: Machst du mit? = Will you join in?",example:"A: Wir spielen Fußball. Machst du mit?\nB: Ja, ich mache gerne mit!",exampleSrc:"A: We're playing football. Will you join in?\nB: Yes, I'd love to join in!",funFact:"Mitmachen is the friendliest invitation word in German. Machst du mit? is how most activities start."},
{type:"teach",trg:"treffen",src:"to meet",pos:"verb",gender:null,note:"Irregular: du triffst, er trifft. Sich treffen = to meet up (reflexive).",example:"A: Wann treffen wir uns?\nB: Lass uns um drei Uhr treffen.",exampleSrc:"A: When are we meeting?\nB: Let's meet at three o'clock.",funFact:"Treffen also means to hit a target. Ein Treffer is a hit or a goal in football."},
{type:"teach",trg:"tun",src:"to do",pos:"verb",gender:null,note:"Irregular: ich tue, du tust, er tut. Very common in spoken German.",example:"A: Was tust du gerade?\nB: Ich tue nichts. Ich bin müde.",exampleSrc:"A: What are you doing right now?\nB: I'm doing nothing. I'm tired.",funFact:"Tun is slightly more informal than machen. Was tun? (What to do?) is a classic German phrase of indecision."},
{type:"mc",q:"'Machst du mit?' bedeutet:",opts:["Nimmst du teil?","Hast du Spaß?","Bist du fertig?","Machst du das kaputt?"],ans:"Nimmst du teil?",hint:"Mitmachen means to join in or participate."},
{type:"mc",q:"Which verb means 'to register or sign up'?",opts:["ankreuzen","anmelden","ausfüllen","abgeben"],ans:"anmelden",hint:"Think of putting your name on a list."},
{type:"fb",s:"Ich {1} heute Abend ein bisschen fern.",a:"sehe",opts:["sehe","mache","gebe","fülle"],hint:"This separable verb is about watching from far away.",sSrc:"I watch a bit of TV tonight."},
{type:"mc",q:"'Du fehlst mir' means...",opts:["You are wrong","You are late","I miss you","I need you"],ans:"I miss you",hint:"The subject is the person who is absent, not the speaker."},
{type:"fb",s:"Wir {1} uns morgen um zehn Uhr.",a:"treffen",opts:["treffen","machen","leben","glauben"],hint:"This irregular verb means to meet up with someone.",sSrc:"We meet tomorrow at ten o'clock."},
{type:"mc",q:"Was bedeutet 'kümmern'?",opts:["to allow / permit","to click on","to tell / narrate","to care / take care of"],ans:"to care / take care of",hint:"Reflexive: 'sich ___ um' = to look after someone or something. Related to 'Kummer' (worry)."}
]},

{id:"deu_r6l17",title:"Zeit und Feste",icon:"🎊",xp:15,board:true,steps:[
{type:"intro",title:"Zeit und Feste",desc:"Time expressions, holidays, and celebrations in German culture.",goals:["Learn 20 words for time, holidays, and celebrations","Practice using time-related nouns with articles","Talk about events and special occasions"]},
{type:"teach",trg:"das Ende",src:"the end",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Enden. Am Ende = in the end.",example:"A: Wann ist das Ende vom Film?\nB: Um zehn Uhr. Es dauert noch eine Stunde.",exampleSrc:"A: When is the end of the movie?\nB: At ten o'clock. It lasts another hour.",funFact:"Ende gut, alles gut (all's well that ends well) is a beloved German proverb borrowed from Shakespeare."},
{type:"teach",trg:"das Jahr",src:"the year",pos:"noun",gender:"n",note:"Neuter noun. Plural: die Jahre. Dieses Jahr = this year.",example:"A: Wie viele Jahre lebst du schon in Berlin?\nB: Ich lebe seit drei Jahren hier.",exampleSrc:"A: How many years have you lived in Berlin?\nB: I've lived here for three years.",funFact:"Jahrgang means both a year's vintage of wine and the year someone was born. Germans ask Welcher Jahrgang bist du?"},
{type:"teach",trg:"der Moment",src:"the moment",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Momente. Einen Moment bitte! = One moment please!",example:"A: Hast du kurz Zeit?\nB: Einen Moment bitte, ich bin gleich fertig.",exampleSrc:"A: Do you have a moment?\nB: One moment please, I'll be done shortly.",funFact:"Im Moment means 'at the moment.' Germans also say Momentmal! as a quick 'hold on!'"},
{type:"teach",trg:"die Zeit",src:"the time",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Zeiten. Es ist Zeit = It is time.",example:"A: Hast du Zeit am Samstag?\nB: Ja, ich habe den ganzen Tag Zeit.",exampleSrc:"A: Do you have time on Saturday?\nB: Yes, I have time all day.",funFact:"Zeit ist Geld (time is money) is used as often in German as in English. Germans take punctuality very seriously."},
{type:"teach",trg:"der Sonnabend",src:"Saturday (northern German)",pos:"noun",gender:"m",note:"Masculine noun. Used in northern and eastern Germany instead of Samstag.",example:"A: Arbeitest du am Sonnabend?\nB: Nein, am Sonnabend habe ich frei.",exampleSrc:"A: Do you work on Saturday?\nB: No, I have Saturday off.",funFact:"Northern Germans say Sonnabend (sun evening), southern Germans say Samstag (from Sabbath). Both are correct!"},
{type:"match",pairs:[{trg:"das Jahr",src:"the year"},{trg:"der Moment",src:"the moment"},{trg:"die Zeit",src:"the time"},{trg:"der Sonnabend",src:"Saturday (northern German)"}]},
{type:"teach",trg:"der Wochentag",src:"the weekday",pos:"noun",gender:"m",note:"COMPOUND: Wochen (week) + Tag (day).\nMasculine noun. Plural: die Wochentage. Compound: Woche + Tag.",example:"A: An welchem Wochentag hast du frei?\nB: Am Mittwoch habe ich immer frei.",exampleSrc:"A: On which weekday do you have off?\nB: I always have Wednesdays off.",funFact:"German weekdays are named after Norse gods and celestial bodies: Montag (moon), Dienstag (Tyr), Mittwoch (midweek)."},
{type:"teach",trg:"der Feierabend",src:"the end of the work day",pos:"noun",gender:"m",note:"Masculine noun. Feierabend machen = to call it a day.",example:"A: Wann machst du Feierabend?\nB: Um fünf Uhr. Dann gehe ich nach Hause.",exampleSrc:"A: When do you finish work?\nB: At five o'clock. Then I go home.",funFact:"Feierabend literally means 'celebration evening.' Germans take their after-work time very seriously. It is sacred rest time."},
{type:"mc",q:"'Feierabend machen' bedeutet:",opts:["den Arbeitstag beenden","zusammen ein Fest feiern","den Abend genießen","eine Feier planen"],ans:"den Arbeitstag beenden",hint:"The end of the work day. Time to stop working."},
{type:"fb",s:"Hast du {1} am Samstag?",a:["Zeit"],opts:["Zeit","Ende","Moment","Jahr"],hint:"Do you have free hours available?",sSrc:"Do you have time on Saturday?"},
{type:"teach",trg:"der Feiertag",src:"the public holiday",pos:"noun",gender:"m",note:"COMPOUND: Feier (celebration) + Tag (day).\nMasculine noun. Plural: die Feiertage. Germany has many regional holidays.",example:"A: Ist morgen ein Feiertag?\nB: Ja, morgen ist alles geschlossen.",exampleSrc:"A: Is tomorrow a public holiday?\nB: Yes, everything is closed tomorrow.",funFact:"Germany has between 9 and 13 public holidays depending on the state. Bavaria has the most!"},
{type:"teach",trg:"die Pause",src:"the break / pause",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Pausen. Eine Pause machen = to take a break.",example:"A: Ich bin so müde.\nB: Mach doch eine Pause!",exampleSrc:"A: I'm so tired.\nB: Take a break!",funFact:"German schools have die große Pause (big break, 15-20 min) where kids play outside, rain or shine."},
{type:"teach",trg:"das Glück",src:"luck / happiness",pos:"noun",gender:"n",note:"Neuter noun. No plural in this meaning. Viel Glück! = Good luck!",example:"A: Morgen habe ich meine Prüfung.\nB: Viel Glück! Du schaffst das!",exampleSrc:"A: Tomorrow I have my exam.\nB: Good luck! You can do it!",funFact:"Glück means both luck AND happiness in German. A Glückspilz (lucky mushroom) is a lucky person."},
{type:"teach",trg:"der Glückwunsch",src:"the congratulations",pos:"noun",gender:"m",note:"COMPOUND: Glück (luck/happiness) + Wunsch (wish).\nMasculine noun. Plural: die Glückwünsche. Herzlichen Glückwunsch! = Congratulations!",example:"A: Ich habe die Prüfung bestanden!\nB: Herzlichen Glückwunsch!",exampleSrc:"A: I passed the exam!\nB: Congratulations!",funFact:"Herzlichen Glückwunsch zum Geburtstag is the full way to say Happy Birthday. Literally: heartfelt luck-wish for the birthday."},
{type:"teach",trg:"die Hochzeit",src:"the wedding",pos:"noun",gender:"f",note:"COMPOUND: Hoch (high) + Zeit (time).\nFeminine noun. Plural: die Hochzeiten. Literally: high time.",example:"A: Wann ist die Hochzeit?\nB: Im Juni. Die Feier ist im Garten.",exampleSrc:"A: When is the wedding?\nB: In June. The celebration is in the garden.",funFact:"Hochzeit literally means 'high time' or 'best time.' A Hochzeitstorte (wedding cake) is often multi-layered."},
{type:"mc",q:"Was sagt man, wenn jemand Geburtstag hat?",opts:["Viel Glück!","Herzlichen Glückwunsch!","Guten Appetit!","Gute Nacht!"],ans:"Herzlichen Glückwunsch!",hint:"The standard birthday congratulation phrase in German."}
,
{"type":"mc","q":"Was ist 'die Pause'?","opts":["the break","the lesson","the meeting","the speech"],"ans":"the break","hint":"A short rest between activities."}]},
{id:"deu_r6l17b",title:"Zeit und Feste (Teil 2)",icon:"🎊",xp:15,board:true,steps:[
{type:"intro",title:"Zeit und Feste (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"der Verein",src:"the club / association",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Vereine. Central to German social life.",example:"A: Bist du in einem Verein?\nB: Ja, ich bin im Sportverein.",exampleSrc:"A: Are you in a club?\nB: Yes, I'm in the sports club.",funFact:"Germany has over 600,000 Vereine. There is a saying: Drei Deutsche, ein Verein (three Germans, one club)."},
{type:"teach",trg:"die Gruppe",src:"the group",pos:"noun",gender:"f",note:"Feminine noun. Plural: die Gruppen. Gruppenarbeit = group work.",example:"A: Wie groß ist deine Gruppe?\nB: Wir sind fünf Personen in der Gruppe.",exampleSrc:"A: How big is your group?\nB: We are five people in the group.",funFact:"Gruppenarbeit (group work) is extremely common in German schools and universities. Teamwork is highly valued."},
{type:"teach",trg:"das Frühjahr",src:"spring (formal)",pos:"noun",gender:"n",note:"Neuter noun. More formal than Frühling. Früh = early + Jahr = year.",example:"A: Wann blühen die Blumen?\nB: Im Frühjahr, meistens im April.",exampleSrc:"A: When do the flowers bloom?\nB: In spring, mostly in April.",funFact:"Frühjahr is used more in writing and news. Frühling is the everyday word. Both mean the early part of the year."},
{type:"teach",trg:"der Wind",src:"the wind",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Winde. Es ist windig = It is windy.",example:"A: Warum ist es so kalt?\nB: Der Wind ist heute sehr stark.",exampleSrc:"A: Why is it so cold?\nB: The wind is very strong today.",funFact:"Germany's North Sea coast is famous for strong winds. Windenergie (wind energy) provides over 25% of Germany's electricity."},
{type:"teach",trg:"beginnen",src:"to begin",pos:"verb",gender:null,note:"Irregular past: begann, hat begonnen. Formal alternative to anfangen.",example:"A: Wann beginnt der Kurs?\nB: Er beginnt um neun Uhr.",exampleSrc:"A: When does the course begin?\nB: It begins at nine o'clock.",funFact:"Beginnen is slightly more formal than anfangen. In writing, beginnen is preferred. In speech, both work."},
{type:"fb",s:"Bist du in einem {1}?",a:["Verein"],opts:["Verein","Gruppe","Wind","Moment"],hint:"A club or association. Central to German social life.",sSrc:"Are you in a club?"},
{type:"teach",trg:"enden",src:"to end",pos:"verb",gender:null,note:"Regular verb. Das Ende = the end (noun). Enden can also mean to finish.",example:"A: Wann endet das Konzert?\nB: Es endet um elf Uhr.",exampleSrc:"A: When does the concert end?\nB: It ends at eleven o'clock.",funFact:"Endlich! means 'finally!' in German. It comes from Ende and expresses relief that something is over."},
{type:"teach",trg:"gratulieren",src:"to congratulate",pos:"verb",gender:null,note:"Regular verb. Ich gratuliere dir! = I congratulate you!",example:"A: Ich habe einen neuen Job!\nB: Toll! Ich gratuliere dir!",exampleSrc:"A: I got a new job!\nB: Great! I congratulate you!",funFact:"Germans gratulieren for birthdays, exams, weddings, and new jobs. It is always followed by the dative (dir, Ihnen)."},
{type:"teach",trg:"heiraten",src:"to marry",pos:"verb",gender:null,note:"Regular verb. Die Heirat = marriage (noun). Wir heiraten! = We're getting married!",example:"A: Wann heiratet ihr?\nB: Wir heiraten im September.",exampleSrc:"A: When are you getting married?\nB: We're getting married in September.",funFact:"In Germany, you must have a civil ceremony at the Standesamt (registry office). A church wedding alone is not legally binding."},
{type:"mc",q:"What does 'der Feierabend' mean?",opts:["the end of the work day","the public holiday","the celebration","a normal weekend day off"],ans:"the end of the work day",hint:"After finishing your professional obligations, this is the moment of freedom."},
{type:"fb",s:"Herzlichen {1} zum Geburtstag!",a:"Glückwunsch",opts:["Glückwunsch","Glück","Hochzeit","Feiertag"],hint:"This compound noun combines luck and wish.",sSrc:"Happy birthday congratulations!"},
{type:"mc",q:"Which word is the formal way to say 'spring'?",opts:["die Frühzeit","das Frühjahr","der Frühstart","der Frühling"],ans:"das Frühjahr",hint:"This compound combines 'early' with 'year.'"},
{type:"fb",s:"Wann {1} der Kurs? Um neun Uhr.",a:"beginnt",opts:["beginnt","endet","macht","geht"],hint:"This is the formal verb for starting something.",sSrc:"When does the course begin? At nine o'clock."},
{type:"mc",q:"Was bedeutet 'beginnen'?",opts:["to congratulate","spring (formal)","to begin","the group"],ans:"to begin",hint:"An irregular strong verb. Shares roots with many Germanic languages. Past: begann, begonnen."},
{type:"fb",s:"Wie sagt man 'to congratulate' auf Deutsch? {1}",a:["gratulieren"],opts:["das Jahr","gratulieren","der Wochentag","das Ende"],hint:"From Latin 'gratulari.' You do this on birthdays: 'Herzlichen Glückwunsch!'",sSrc:"How do you say 'to congratulate' in German?"},
{type:"mc",q:"Was bedeutet 'heiraten'?",opts:["to end","the group","the public holiday","to marry"],ans:"to marry",hint:"What couples do at a wedding. Related to 'die Heirat' (marriage). Rings and vows involved."}
]},

{id:"deu_r6l18",title:"Noch mehr Verben",icon:"💪",xp:15,board:true,steps:[
{type:"intro",title:"Noch mehr Verben",desc:"Essential remaining verbs, adjectives, and time expressions to round out your A1 vocabulary.",goals:["Learn 18 remaining essential words","Master time adverbs and adjectives","Use common verb phrases in context"]},
{type:"teach",trg:"wehtun",src:"to hurt / ache",pos:"verb",gender:null,note:"Separable: Es tut weh = It hurts. Mir tut der Kopf weh = My head hurts.",example:"A: Was ist los?\nB: Mein Bauch tut weh. Ich brauche eine Pause.",exampleSrc:"A: What's wrong?\nB: My stomach hurts. I need a break.",funFact:"Germans point to the body part and say Es tut weh. Weh is an old word for pain, related to English 'woe.'"},
{type:"teach",trg:"warten",src:"to wait",pos:"verb",gender:null,note:"Regular verb. Warten auf + accusative = to wait for.",example:"A: Worauf wartest du?\nB: Ich warte auf den Bus. Er kommt in fünf Minuten.",exampleSrc:"A: What are you waiting for?\nB: I'm waiting for the bus. It comes in five minutes.",funFact:"Warten auf has a fixed preposition (auf). Der Warteraum (waiting room) is found in every German doctor's office."},
{type:"teach",trg:"Rad fahren",src:"to ride a bicycle",pos:"verb",gender:null,note:"Written separately in infinitive. Ich fahre Rad. Das Fahrrad = bicycle.",example:"A: Wie kommst du zur Arbeit?\nB: Ich fahre jeden Tag Rad.",exampleSrc:"A: How do you get to work?\nB: I ride my bicycle every day.",funFact:"Germany has over 75,000 km of bike paths. Rad fahren is the main transport for many Germans, especially in cities like Munster."},
{type:"teach",trg:"aus sein",src:"to be off / finished",pos:"verb",gender:null,note:"Phrase with sein. Das Licht ist aus = The light is off. Die Schule ist aus = School is over.",example:"A: Ist die Schule schon aus?\nB: Ja, seit einer Stunde.",exampleSrc:"A: Is school already over?\nB: Yes, since an hour ago.",funFact:"Aus sein is incredibly versatile. Es ist aus (it's over) can refer to lights, relationships, school, or events."},
{type:"teach",trg:"weg sein",src:"to be gone / away",pos:"verb",gender:null,note:"Phrase with sein. Er ist weg = He is gone. Weg! = Go away!",example:"A: Wo ist mein Handy?\nB: Es ist weg! Hast du es verloren?",exampleSrc:"A: Where is my phone?\nB: It's gone! Did you lose it?",funFact:"Weg as a noun means path (der Weg). As a particle it means away/gone. Two completely different meanings!"},
{type:"match",pairs:[{trg:"warten",src:"to wait"},{trg:"Rad fahren",src:"to ride a bicycle"},{trg:"aus sein",src:"to be off / finished"},{trg:"weg sein",src:"to be gone / away"}]},
{type:"teach",trg:"zu sein",src:"to be closed",pos:"verb",gender:null,note:"Phrase with sein. Der Laden ist zu = The shop is closed. Opposite: auf sein.",example:"A: Gehen wir zum Supermarkt?\nB: Er ist schon zu. Es ist nach acht.",exampleSrc:"A: Shall we go to the supermarket?\nB: It's already closed. It's past eight.",funFact:"German shops close earlier than in many countries. Zu sein after 8 PM is normal. On Sundays, almost everything ist zu."},
{type:"mc",q:"Der Supermarkt ist schon ___. Es ist nach acht.",opts:["zu","auf","weg","aus"],ans:"zu",hint:"Closed. The opposite of open."},
{type:"fb",s:"Mein Handy ist {1}! Ich kann es nicht finden.",a:["weg"],opts:["weg","aus","zu","tot"],hint:"Gone, disappeared. Not here anymore.",sSrc:"My phone is gone! I cannot find it."},
{type:"teach",trg:"wiederholen",src:"to repeat / review",pos:"verb",gender:null,note:"Not separable in this meaning. Können Sie das bitte wiederholen? = Can you repeat that?",example:"A: Ich habe das nicht verstanden.\nB: Kein Problem, ich wiederhole es gerne.",exampleSrc:"A: I didn't understand that.\nB: No problem, I'll gladly repeat it.",funFact:"Wiederholen literally means to fetch again (wieder + holen). In language class, you will hear Bitte wiederholen! constantly."},
{type:"teach",trg:"das Leben",src:"the life",pos:"noun",gender:"n",note:"Neuter noun. No plural in this meaning. Das ist das Leben! = That's life!",example:"A: Wie ist das Leben in Deutschland?\nB: Es ist gut, aber manchmal stressig.",exampleSrc:"A: How is life in Germany?\nB: It's good, but sometimes stressful.",funFact:"Lebensqualität (quality of life) is something Germans take very seriously. German cities regularly rank in top global livability lists."},
{type:"teach",trg:"der Plan",src:"the plan",pos:"noun",gender:"m",note:"Masculine noun. Plural: die Pläne. Note the umlaut in plural!",example:"A: Was sind deine Pläne für das Wochenende?\nB: Ich habe noch keine Pläne.",exampleSrc:"A: What are your plans for the weekend?\nB: I don't have any plans yet.",funFact:"Germans love planning. Der Fahrplan (schedule), der Stadtplan (city map), der Lehrplan (curriculum) all have Plan in them."},
{type:"teach",trg:"der Fußball",src:"football / soccer",pos:"noun",gender:"m",note:"Masculine noun. Literally: foot + ball. Die Bundesliga is the top league.",example:"A: Spielst du gerne Fußball?\nB: Ja, jeden Samstag im Verein!",exampleSrc:"A: Do you like playing football?\nB: Yes, every Saturday at the club!",funFact:"Fußball is practically a religion in Germany. The Bundesliga is one of the most-watched leagues in the world."},
{type:"mc",q:"Was sind deine Pläne? Die Mehrzahl von 'Plan' ist:",opts:["die Planen","die Pläne","die Plans","die Plane"],ans:"die Pläne",hint:"Umlaut in the plural. A to Ä."}
]},
{id:"deu_r6l18b",title:"Noch mehr Verben (Teil 2)",icon:"💪",xp:15,board:true,steps:[
{type:"intro",title:"Noch mehr Verben (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"glücklich",src:"happy",pos:"adj",gender:null,note:"Adjective. Opposite: unglücklich (unhappy). From Glück (luck/happiness).",example:"A: Bist du glücklich hier?\nB: Ja, ich bin sehr glücklich in dieser Stadt.",exampleSrc:"A: Are you happy here?\nB: Yes, I am very happy in this city.",funFact:"Glücklich combines luck and happiness. Germans might say Ich bin glücklich for deep contentment, froh for momentary gladness."},
{type:"teach",trg:"tot",src:"dead",pos:"adj",gender:null,note:"Adjective. Der Tod = death (noun). Totmüde = dead tired (colloquial).",example:"A: Lebt der Fisch noch?\nB: Nein, er ist leider tot.",exampleSrc:"A: Is the fish still alive?\nB: No, it's unfortunately dead.",funFact:"Totmüde (dead tired), totlachen (to die laughing), totschweigen (to kill with silence): German loves tot- as an intensifier."},
{type:"teach",trg:"früher",src:"earlier / in the past",pos:"adv",gender:null,note:"Comparative of früh (early). Also means 'back then, in the old days.'",example:"A: Wie war das Leben früher?\nB: Früher war alles anders.",exampleSrc:"A: How was life in the past?\nB: Everything was different back then.",funFact:"Früher war alles besser (everything was better in the past) is a classic German phrase, usually said with a sigh."},
{type:"teach",trg:"letzt",src:"last (previous)",pos:"adj",gender:null,note:"Adjective. Always with ending: letzte Woche, letztes Jahr, letzten Montag.",example:"A: Wann warst du im Kino?\nB: Letzte Woche. Der Film war toll.",exampleSrc:"A: When were you at the cinema?\nB: Last week. The movie was great.",funFact:"Letzt always needs an adjective ending in German. You cannot say just letzt. It is always letzte/letztes/letzten depending on the noun."},
{type:"teach",trg:"nächst",src:"next",pos:"adj",gender:null,note:"Adjective. Always with ending: nächste Woche, nächstes Jahr, nächsten Montag.",example:"A: Wann fährst du in den Urlaub?\nB: Nächste Woche. Ich freue mich!",exampleSrc:"A: When are you going on vacation?\nB: Next week. I'm looking forward to it!",funFact:"Nächst also means nearest: die nächste Haltestelle (the next/nearest stop). Context tells you which meaning."},
{type:"match",pairs:[{trg:"tot",src:"dead"},{trg:"früher",src:"earlier / in the past"},{trg:"letzt",src:"last (previous)"},{trg:"nächst",src:"next"}]},
{type:"teach",trg:"später",src:"later",pos:"adv",gender:null,note:"Comparative of spät (late). Bis später! = See you later!",example:"A: Kommst du jetzt?\nB: Nein, ich komme später. Bis später!",exampleSrc:"A: Are you coming now?\nB: No, I'll come later. See you later!",funFact:"Bis später is one of the most common German goodbyes. Spätestens means 'at the latest.'"},
{type:"teach",trg:"heute",src:"today",pos:"adv",gender:null,note:"Adverb. Heute Morgen = this morning. Heute Abend = tonight.",example:"A: Was machst du heute?\nB: Heute gehe ich einkaufen und dann ins Kino.",exampleSrc:"A: What are you doing today?\nB: Today I'm going shopping and then to the cinema.",funFact:"Heutzutage means 'nowadays.' Heute is related to English 'today' through the Germanic root for 'this day.'"},
{type:"teach",trg:"bis",src:"until / by",pos:"prep",gender:null,note:"Preposition. Bis morgen! = See you tomorrow! Bis wann? = Until when?",example:"A: Bis wann bist du im Büro?\nB: Bis fünf Uhr. Dann mache ich Feierabend.",exampleSrc:"A: Until when are you at the office?\nB: Until five o'clock. Then I finish work.",funFact:"Bis is one of the most useful small words. Bis bald (see you soon), bis gleich (see you in a moment), bis dann (see you then)."},
{type:"fb",s:"{1} Woche war ich im Kino.",a:["Letzte"],opts:["Letzte","Nächste","Heute","Morgen"],hint:"The previous week. Always needs an adjective ending.",sSrc:"Last week I was at the cinema."},
{type:"mc",q:"What does 'wehtun' mean?",opts:["to hurt / ache","to wait","to repeat","to be gone"],ans:"to hurt / ache",hint:"Think of something causing pain in your body."},
{type:"fb",s:"Ich {1} auf den Bus. Er kommt bald.",a:"warte",opts:["warte","fahre","bin","mache"],hint:"This regular verb takes the preposition 'auf' for what you expect.",sSrc:"I wait for the bus. It is coming soon."},
{type:"mc",q:"'Bis später' means...",opts:["Good morning","See you later","Goodbye forever","Until tomorrow"],ans:"See you later",hint:"Bis means until. Später means at a following time."},
{type:"fb",s:"Letzte {1} war ich im Kino.",a:"Woche",opts:["Woche","Tag","Jahr","Monat"],hint:"Seven days make up this time period.",sSrc:"Last week I was at the cinema."},
{type:"mc",q:"Was bedeutet 'glücklich'?",opts:["to be gone / away","later","happy","football / soccer"],ans:"happy",hint:"From 'Glück' (luck/happiness) + '-lich' suffix. The feeling when everything goes well."},
{type:"fb",s:"Wie war das Leben {1}?",a:["früher"],opts:["aus sein","zu sein","tot","früher"],hint:"Comparative form of 'früh' (early). Used as an adverb meaning 'in earlier times.'",sSrc:"How was life in the past?"}
,{type:"match",pairs:[{trg:"der Hunger",src:"hunger"},{trg:"spazieren gehen",src:"to go for a walk"},{trg:"die Minute / die Sekunde",src:"minute / second"},{trg:"pünktlich",src:"punctual / on time"},{trg:"der Nachmittag / der Vormittag",src:"afternoon / morning (before noon)"},{trg:"der Schluss",src:"the end / closing time"}]},{type:"match",pairs:[{trg:"wichtig / eilig",src:"important / urgent"},{trg:"das Telefon / telefonieren",src:"telephone / to call"},{trg:"das Gesicht / der Zeh",src:"face / toe"},{trg:"der Arzt / die Ärztin",src:"the doctor (m/f)"},{trg:"der Schmerz / die Erkältung",src:"pain / cold (illness)"},{trg:"weh tun",src:"to hurt"}]},{type:"match",pairs:[{trg:"die Halle",src:"the hall, the large room"},{trg:"die Musik / das Konzert",src:"music / concert"},{trg:"malen / fotografieren",src:"to paint / to photograph"},{trg:"die Feier / die Party",src:"celebration / party"},{trg:"die Klasse",src:"the class/classroom"},{trg:"die Maschine",src:"the machine"}]},{type:"match",pairs:[{trg:"der Test",src:"the test"},{trg:"der Unterricht",src:"the lesson/instruction"},{trg:"der Doktor",src:"the doctor/PhD"},{trg:"das Ergebnis",src:"the result"},{trg:"der Bogen",src:"the sheet (of paper)/form"},{trg:"der Buchstabe",src:"the letter (of the alphabet)"}]},{type:"match",pairs:[{trg:"das Papier",src:"the paper"},{trg:"die Vorwahl",src:"the area code"},{trg:"die CD",src:"the CD"},{trg:"automatisch",src:"automatic"},{trg:"benutzen",src:"to use"},{trg:"erlauben",src:"to allow / permit"}]},{type:"match",pairs:[{trg:"erzählen",src:"to tell / narrate"},{trg:"vorstellen",src:"to introduce / imagine"},{trg:"fehlen",src:"to be missing / absent"},{trg:"gewinnen",src:"to win"},{trg:"glauben",src:"to believe"},{trg:"kümmern",src:"to care / take care of"}]},{type:"match",pairs:[{trg:"lachen",src:"to laugh"},{trg:"leben",src:"to live"},{trg:"mitmachen",src:"to participate / join in"},{trg:"der Feierabend",src:"the end of the work day"},{trg:"der Feiertag",src:"the public holiday"},{trg:"die Gruppe",src:"the group"}]},{type:"match",pairs:[{trg:"der Wind",src:"the wind"},{trg:"beginnen",src:"to begin"},{trg:"heiraten",src:"to marry"},{trg:"wehtun",src:"to hurt / ache"},{trg:"wiederholen",src:"to repeat / review"},{trg:"das Leben",src:"the life"}]},{type:"match",pairs:[{trg:"der Fußball",src:"football / soccer"},{trg:"glücklich",src:"happy"},{trg:"heute",src:"today"},{trg:"scheinen",src:"to shine / to seem"},{trg:"der Anruf / anrufen",src:"the call / to call"},{trg:"das Handy",src:"the mobile phone"},{trg:"der Chef / die Chefin",src:"boss (m/f)"},{trg:"bringen / holen",src:"to bring / to fetch"},{trg:"die Anzeige",src:"the advertisement/display"},{trg:"anklicken",src:"to click on"}]}]}

]};

export default UNIT_6;
